    "use strict";

    const ULTRA_ELITE_RENDER_BENCH = document.body?.dataset?.ultraEliteMode === "render-bench";
    const DEV_RENDER_HACK = document.body?.dataset?.ultraEliteDevHack || "";
    const DEV_FORCE_FULL_RENDER = DEV_RENDER_HACK.includes("full-render");
    const DEV_DISABLE_LASER_EFFECTS = DEV_RENDER_HACK.includes("no-lasers");
    const DEV_DISABLE_ENGINE_EFFECTS = DEV_RENDER_HACK.includes("no-engines");
    const ULTRA_ELITE_DEV_SHELL = document.body?.dataset?.ultraEliteMode === "dev";
    const TAU = Math.PI * 2;
    const clamp = (v, lo, hi) => Math.max(lo, Math.min(hi, v));
    const AUDIO_VOLUME_KEY = "ultraEliteAudioVolume";
    const DEFAULT_AUDIO_VOLUME = .8;
    const AUDIO_OUTPUT_GAIN = 1.65;
    const VISUAL_BRIGHTNESS_KEY = "ultraEliteVisualBrightness";
    const DEFAULT_VISUAL_BRIGHTNESS = 1;

    function normalizeAudioVolume(value) {
      const n = Number(value);
      return Number.isFinite(n) ? clamp(n, 0, 1) : DEFAULT_AUDIO_VOLUME;
    }

    function effectiveAudioVolume(value) {
      return normalizeAudioVolume(value) * AUDIO_OUTPUT_GAIN;
    }

    function loadAudioVolumeSetting() {
      try {
        const raw = localStorage.getItem(AUDIO_VOLUME_KEY);
        return raw == null ? DEFAULT_AUDIO_VOLUME : normalizeAudioVolume(raw);
      } catch {
        return DEFAULT_AUDIO_VOLUME;
      }
    }

    function saveAudioVolumeSetting(value) {
      try {
        localStorage.setItem(AUDIO_VOLUME_KEY, String(normalizeAudioVolume(value)));
      } catch {}
    }

    function normalizeVisualBrightness(value) {
      const n = Number(value);
      return Number.isFinite(n) ? clamp(n, .6, 1.4) : DEFAULT_VISUAL_BRIGHTNESS;
    }

    function loadVisualBrightnessSetting() {
      try {
        const raw = localStorage.getItem(VISUAL_BRIGHTNESS_KEY);
        return raw == null ? DEFAULT_VISUAL_BRIGHTNESS : normalizeVisualBrightness(raw);
      } catch {
        return DEFAULT_VISUAL_BRIGHTNESS;
      }
    }

    function saveVisualBrightnessSetting(value) {
      try {
        localStorage.setItem(VISUAL_BRIGHTNESS_KEY, String(normalizeVisualBrightness(value)));
      } catch {}
    }
    const lerp = (a, b, t) => a + (b - a) * t;
    const fmt = (n, d = 1) => Number(n).toFixed(d);
    const byId = (id) => document.getElementById(id);
    const DIAGNOSTIC_LOG_LIMIT = 80;
    const diagnosticEvents = [];

    function diagnosticValue(value) {
      if (value instanceof Error) return `${value.name}: ${value.message}${value.stack ? `\n${value.stack}` : ""}`;
      if (value == null || typeof value === "string" || typeof value === "number" || typeof value === "boolean") return String(value);
      try {
        return JSON.stringify(value);
      } catch {
        return Object.prototype.toString.call(value);
      }
    }

    function recordDiagnosticEvent(kind, args = []) {
      const entry = {
        at: new Date().toISOString(),
        t: Math.round((performance.now ? performance.now() : 0) * 10) / 10,
        kind,
        message: Array.from(args).map(diagnosticValue).join(" ").slice(0, 2200)
      };
      diagnosticEvents.push(entry);
      if (diagnosticEvents.length > DIAGNOSTIC_LOG_LIMIT) diagnosticEvents.splice(0, diagnosticEvents.length - DIAGNOSTIC_LOG_LIMIT);
    }

    (function installDiagnosticsCapture() {
      for (const method of ["log", "info", "warn", "error"]) {
        const original = console[method]?.bind(console);
        if (!original) continue;
        console[method] = (...args) => {
          recordDiagnosticEvent(`console.${method}`, args);
          original(...args);
        };
      }
      window.addEventListener("error", (event) => {
        recordDiagnosticEvent("window.error", [
          event.message || "Script error",
          `${event.filename || "unknown"}:${event.lineno || 0}:${event.colno || 0}`,
          event.error || ""
        ]);
      });
      window.addEventListener("unhandledrejection", (event) => {
        recordDiagnosticEvent("unhandledrejection", [event.reason || "unknown rejection"]);
      });
      recordDiagnosticEvent("boot", [`mode=${ULTRA_ELITE_DEV_SHELL ? "dev" : ULTRA_ELITE_RENDER_BENCH ? "render-bench" : "game"}`]);
    })();

    function hash32(str) {
      let h = 2166136261 >>> 0;
      for (let i = 0; i < str.length; i++) {
        h ^= str.charCodeAt(i);
        h = Math.imul(h, 16777619);
      }
      return h >>> 0;
    }

    function mulberry(seed) {
      let a = seed >>> 0;
      return () => {
        a += 0x6D2B79F5;
        let t = a;
        t = Math.imul(t ^ (t >>> 15), t | 1);
        t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
      };
    }

    function vec(x = 0, y = 0, z = 0) {
      return { x, y, z };
    }

    function finiteVec3(v) {
      return !!v && Number.isFinite(v.x) && Number.isFinite(v.y) && Number.isFinite(v.z);
    }

    function finiteQuat(q) {
      return !!q && Number.isFinite(q.w) && Number.isFinite(q.x) && Number.isFinite(q.y) && Number.isFinite(q.z);
    }

    function add(a, b) {
      return vec(a.x + b.x, a.y + b.y, a.z + b.z);
    }

    function sub(a, b) {
      return vec(a.x - b.x, a.y - b.y, a.z - b.z);
    }

    function scale(a, n) {
      return vec(a.x * n, a.y * n, a.z * n);
    }

    function len(a) {
      return Math.hypot(a.x, a.y, a.z);
    }

    function norm(a) {
      if (!finiteVec3(a)) return vec();
      const l = len(a);
      if (!Number.isFinite(l) || l <= 1e-9) return vec();
      return scale(a, 1 / l);
    }

    function rotatePoint(p, yaw, pitch, roll) {
      let x = p.x, y = p.y, z = p.z;
      let cy = Math.cos(yaw), sy = Math.sin(yaw);
      let x1 = x * cy - z * sy;
      let z1 = x * sy + z * cy;
      x = x1; z = z1;
      let cp = Math.cos(pitch), sp = Math.sin(pitch);
      let y1 = y * cp - z * sp;
      z1 = y * sp + z * cp;
      y = y1; z = z1;
      let cr = Math.cos(roll), sr = Math.sin(roll);
      x1 = x * cr - y * sr;
      y1 = x * sr + y * cr;
      return vec(x1, y1, z);
    }

    function rotateShipPoint(p, yaw, pitch, roll = 0) {
      const right = rotatePoint(vec(1, 0, 0), yaw, pitch, 0);
      const up = rotatePoint(vec(0, 1, 0), yaw, pitch, 0);
      const forward = rotatePoint(vec(0, 0, 1), yaw, pitch, 0);
      const cr = Math.cos(roll), sr = Math.sin(roll);
      const rolledRight = add(scale(right, cr), scale(up, sr));
      const rolledUp = add(scale(up, cr), scale(right, -sr));
      return add(add(scale(rolledRight, p.x), scale(rolledUp, p.y)), scale(forward, p.z));
    }

    function quat(w = 1, x = 0, y = 0, z = 0) {
      return { w, x, y, z };
    }

    function quatNorm(q) {
      if (!finiteQuat(q)) return quat();
      const l = Math.hypot(q.w, q.x, q.y, q.z);
      if (!Number.isFinite(l) || l <= 1e-9) return quat();
      return quat(q.w / l, q.x / l, q.y / l, q.z / l);
    }

    function quatMul(a, b) {
      return quat(
        a.w * b.w - a.x * b.x - a.y * b.y - a.z * b.z,
        a.w * b.x + a.x * b.w + a.y * b.z - a.z * b.y,
        a.w * b.y - a.x * b.z + a.y * b.w + a.z * b.x,
        a.w * b.z + a.x * b.y - a.y * b.x + a.z * b.w
      );
    }

    function quatConj(q) {
      return quat(q.w, -q.x, -q.y, -q.z);
    }

    function quatFromAxisAngle(axis, angle) {
      const n = norm(axis);
      const s = Math.sin(angle / 2);
      return quat(Math.cos(angle / 2), n.x * s, n.y * s, n.z * s);
    }

    function quatRotate(q, p) {
      const r = quatMul(quatMul(q, quat(0, p.x, p.y, p.z)), quatConj(q));
      return vec(r.x, r.y, r.z);
    }

    function quatSlerp(a, b, t) {
      t = clamp(t, 0, 1);
      a = quatNorm(a);
      b = quatNorm(b);
      let cos = a.w * b.w + a.x * b.x + a.y * b.y + a.z * b.z;
      if (cos < 0) {
        b = quat(-b.w, -b.x, -b.y, -b.z);
        cos = -cos;
      }
      if (cos > .9995) {
        return quatNorm(quat(
          lerp(a.w, b.w, t),
          lerp(a.x, b.x, t),
          lerp(a.y, b.y, t),
          lerp(a.z, b.z, t)
        ));
      }
      const theta = Math.acos(clamp(cos, -1, 1));
      const sinTheta = Math.sin(theta) || 1;
      const s0 = Math.sin((1 - t) * theta) / sinTheta;
      const s1 = Math.sin(t * theta) / sinTheta;
      return quatNorm(quat(
        a.w * s0 + b.w * s1,
        a.x * s0 + b.x * s1,
        a.y * s0 + b.y * s1,
        a.z * s0 + b.z * s1
      ));
    }

    function cross(a, b) {
      return vec(
        a.y * b.z - a.z * b.y,
        a.z * b.x - a.x * b.z,
        a.x * b.y - a.y * b.x
      );
    }

    function dot(a, b) {
      return a.x * b.x + a.y * b.y + a.z * b.z;
    }

    function quatFromBasis(right, up, forward) {
      const m00 = right.x, m01 = up.x, m02 = forward.x;
      const m10 = right.y, m11 = up.y, m12 = forward.y;
      const m20 = right.z, m21 = up.z, m22 = forward.z;
      const tr = m00 + m11 + m22;
      if (tr > 0) {
        const s = Math.sqrt(tr + 1) * 2;
        return quatNorm(quat(.25 * s, (m21 - m12) / s, (m02 - m20) / s, (m10 - m01) / s));
      }
      if (m00 > m11 && m00 > m22) {
        const s = Math.sqrt(1 + m00 - m11 - m22) * 2;
        return quatNorm(quat((m21 - m12) / s, .25 * s, (m01 + m10) / s, (m02 + m20) / s));
      }
      if (m11 > m22) {
        const s = Math.sqrt(1 + m11 - m00 - m22) * 2;
        return quatNorm(quat((m02 - m20) / s, (m01 + m10) / s, .25 * s, (m12 + m21) / s));
      }
      const s = Math.sqrt(1 + m22 - m00 - m11) * 2;
      return quatNorm(quat((m10 - m01) / s, (m02 + m20) / s, (m12 + m21) / s, .25 * s));
    }

    function quatLookRotation(forward, upHint = vec(0, 1, 0)) {
      const f = norm(forward);
      if (!finiteVec3(f) || len(f) <= 1e-9) return quat();
      let r = cross(upHint, f);
      if (len(r) < .001) r = cross(vec(1, 0, 0), f);
      r = norm(r);
      const u = norm(cross(f, r));
      return quatFromBasis(r, u, f);
    }

    function ensureCameraQuat(camera) {
      if (!camera.q) camera.q = quat();
      camera.q = quatNorm(camera.q);
      return camera.q;
    }

    function ensureCameraState(camera) {
      if (!camera) return makeCamera(-850);
      if (!finiteVec3(camera.pos)) camera.pos = vec(0, 0, -850);
      ensureCameraQuat(camera);
      return camera;
    }

    function makeCamera(z) {
      return { pos: vec(0, 0, z), q: quat() };
    }

    function rotateCameraLocal(camera, axis, angle) {
      camera.q = quatNorm(quatMul(ensureCameraQuat(camera), quatFromAxisAngle(axis, angle)));
    }

    function cameraTransform(world, camera) {
      camera = ensureCameraState(camera);
      if (!finiteVec3(world)) return vec(0, 0, -1);
      const p = sub(world, camera.pos);
      return quatRotate(quatConj(ensureCameraQuat(camera)), p);
    }

    // Rendering-space framework:
    // - World/object geometry: transform 3D points through cameraTransform/worldDirToCam,
    //   then project(). This is the default for ships, stations, rings, planet surfaces,
    //   planet shadows, and any detail that should stay attached while the player rolls.
    // - Screen-space drawing: only for UI, transition tunnels, particles, glows, and
    //   intentional billboards. If a thing is painted on a hull/planet/station surface,
    //   do not draw it with raw ctx.ellipse()/gradients in screen coordinates.
    // - Planet/star surface details have their own helpers near drawPlanetSurface /
    //   drawSunBody. Cracks, clouds, rings and similar marks must be projected from
    //   world/object directions, not clipped onto the canvas, or they will rotate with
    //   the player's view.
    // A ship's own rot/pitch/roll is a world-frame orientation (unaffected by the
    // player's own turning), but rendering combines its rotated model verts with a
    // camera-space position. Any world-frame direction has to pass through this
    // same camera-conjugate rotation before that combination is valid — otherwise
    // every other object's rendered attitude stays screen-locked instead of
    // world-fixed, i.e. it visibly spins in lockstep whenever the player turns.
    function worldDirToCam(dir, camera = game.camera) {
      return quatRotate(quatConj(ensureCameraQuat(camera)), dir);
    }

    function projectWorldPoint(world, w, h, camera = game.camera) {
      return project(cameraTransform(world, camera), w, h);
    }

    function forwardVector(camera) {
      return quatRotate(ensureCameraQuat(camera), vec(0, 0, 1));
    }

    function cameraLocalToWorld(camera, local) {
      return add(camera.pos, quatRotate(ensureCameraQuat(camera), local));
    }

    // Cockpit view directions (fwd/rear/left/right) plus an external chase camera,
    // like the original's view-switching. Steering, weapons and the scanner always
    // work off the real game.camera (the ship); viewCamera() only derives what the
    // flight view is rendered from, swapped in for the duration of drawSpace.
    const VIEW_YAW = { rear: Math.PI, left: -Math.PI / 2, right: Math.PI / 2 };
    const VIEW_LABELS = { fwd: "", rear: "REAR VIEW", left: "LEFT VIEW", right: "RIGHT VIEW", ext: "EXTERNAL VIEW" };
    const MODEL_RENDER_QUALITY = {
      texturePx: 9,
      decalPx: 12,
      detailPx: 10,
      detailDistance: 900,
      detailEdgeDistance: 900,
      damagePx: 16,
      effectPx: 7
    };
    const PERFORMANCE_DPR_CAP = [2, 1.35, 1, .8];
    const PERFORMANCE_PARTICLE_SCALE = [1, .52, .26, .1];
    const PERFORMANCE_LOD_LABELS = ["HIGH", "MED", "LOW", "MIN"];

    function ultraFxEnabled() {
      return game.fxLevel === "ultra";
    }

    function performanceLod() {
      if (DEV_FORCE_FULL_RENDER) return 0;
      return game.performance?.lod || 0;
    }

    function performanceSceneLoad() {
      return clamp(((game.performance?.visibleModels || 0) - 6) / 16, 0, 1);
    }

    function performanceThresholdMul() {
      if (DEV_FORCE_FULL_RENDER) return 1;
      return 1 + performanceLod() * 1.35 + performanceSceneLoad() * 4.5;
    }

    function performanceParticleScale() {
      const floor = performanceLod() >= 3 ? .055 : .1;
      return Math.max(floor, (PERFORMANCE_PARTICLE_SCALE[performanceLod()] ?? .1) * (1 - performanceSceneLoad() * .62));
    }

    function performanceParticleLimit(limit) {
      return Math.max(performanceLod() >= 3 ? 10 : 18, Math.round(limit * performanceParticleScale()));
    }

    function trimParticleStore(store, limit) {
      const cap = performanceParticleLimit(limit);
      if (store.length > cap) store.splice(0, store.length - cap);
    }

    function updatePerformanceBudget(rawDt) {
      const perf = game.performance || (game.performance = { frameMs: 16.7, lod: 0 });
      const ms = clamp(rawDt * 1000, 1, 220);
      perf.frameMs = perf.frameMs ? lerp(perf.frameMs, ms, .1) : ms;
      if (DEV_FORCE_FULL_RENDER) {
        perf.lod = 0;
        perf.lodPressure = 0;
        perf.lodRecovery = 0;
        perf.dprCap = PERFORMANCE_DPR_CAP[0];
        perf.qualityLabel = PERFORMANCE_LOD_LABELS[0];
        if (perf._appliedLod !== 0) {
          perf._appliedLod = 0;
          resizeCanvases();
        }
        return;
      }
      const load = performanceSceneLoad();
      let desired = perf.frameMs > 58 ? 3 : perf.frameMs > 36 ? 2 : perf.frameMs > 24 ? 1 : 0;
      if (load > .88) desired = Math.max(desired, 2);
      else if (load > .55) desired = Math.max(desired, 1);

      const current = perf.lod || 0;
      if (desired > current) {
        perf.lodPressure = (perf.lodPressure || 0) + rawDt * (desired === 3 ? 2.4 : 1.25);
        perf.lodRecovery = 0;
        if (perf.lodPressure > .65) {
          perf.lod = Math.min(3, current + 1);
          perf.lodPressure = 0;
        }
      } else if (desired < current && perf.frameMs < 20 + current * 2 && load < .38) {
        perf.lodRecovery = (perf.lodRecovery || 0) + rawDt;
        perf.lodPressure = 0;
        if (perf.lodRecovery > 4.2) {
          perf.lod = Math.max(0, current - 1);
          perf.lodRecovery = 0;
        }
      } else {
        perf.lodPressure = 0;
        perf.lodRecovery = 0;
      }

      const nextLod = perf.lod || 0;
      perf.dprCap = PERFORMANCE_DPR_CAP[nextLod] || .8;
      perf.qualityLabel = PERFORMANCE_LOD_LABELS[nextLod] || "MIN";
      if (perf._appliedLod !== nextLod) {
        perf._appliedLod = nextLod;
        resizeCanvases();
      }
    }

    function updateScenePerformanceLoad(items) {
      const perf = game.performance || (game.performance = { frameMs: 16.7, lod: 0, dprCap: 2 });
      let visibleModels = 0;
      for (const item of items) {
        const o = item.o;
        if (!o || item.p?.z <= 1) continue;
        if (o.type === "ship" || o.type === "station" || o.type === "hermit" || o.type === "missile") visibleModels++;
      }
      perf.visibleModels = visibleModels;
    }

    function objectSimulationKind(o) {
      if (!o || o._remove) return null;
      if (o.type === "ship") return "ship";
      if (o.type === "station") return "station";
      if (o.type === "sun") return "sun";
      if (o.type === "planet") return "planet";
      if (o.type === "missile") return "missile";
      if (o.type === "asteroid" || o.type === "boulder" || o.type === "splinter" || o.type === "hermit") return "rock";
      if (o.type === "canister" || o.type === "plate") return "cargo";
      return "other";
    }

    function buildWorldSnapshot() {
      const snapshot = {
        frame: (game.worldFrame || 0) + 1,
        objects: [],
        objectSet: new Set(),
        ships: [],
        stations: [],
        stationLike: [],
        planets: [],
        rocks: [],
        cargo: [],
        missiles: [],
        collisionBodies: [],
        largeBodies: [],
        sun: null,
        station: null
      };
      for (const o of game.objects || []) {
        if (!o || o._remove) continue;
        if (o._simId == null) o._simId = game.nextObjectId++;
        snapshot.objects.push(o);
        snapshot.objectSet.add(o);
        const kind = objectSimulationKind(o);
        if (kind === "ship") snapshot.ships.push(o);
        else if (kind === "station") {
          snapshot.stations.push(o);
          snapshot.stationLike.push(o);
          if (!snapshot.station) snapshot.station = o;
        } else if (kind === "sun") {
          snapshot.sun = snapshot.sun || o;
          snapshot.largeBodies.push(o);
        } else if (kind === "planet") {
          snapshot.planets.push(o);
          snapshot.largeBodies.push(o);
        } else if (kind === "rock") {
          snapshot.rocks.push(o);
          if (o.type === "hermit") snapshot.stationLike.push(o);
        } else if (kind === "cargo") {
          snapshot.cargo.push(o);
        } else if (kind === "missile") {
          snapshot.missiles.push(o);
        }
        if (collisionBody(o)) snapshot.collisionBodies.push(o);
        if (largeCollisionBody(o)) snapshot.largeBodies.push(o);
      }
      game.worldFrame = snapshot.frame;
      game.world = snapshot;
      return snapshot;
    }

    function worldSnapshot() {
      return game.world || buildWorldSnapshot();
    }

    function primaryStation() {
      const world = worldSnapshot();
      if (world.station && !world.station._remove) return world.station;
      return world.stations.find((o) => !o._remove) || null;
    }

    function primarySun() {
      const world = worldSnapshot();
      return world.sun && !world.sun._remove ? world.sun : null;
    }

    function isWorldObjectLive(o) {
      return !!o && !o._remove && worldSnapshot().objectSet.has(o);
    }

    function recordSimPhase(name, ms) {
      const perf = game.performance || (game.performance = { frameMs: 16.7, lod: 0 });
      const phases = perf.simPhases || (perf.simPhases = {});
      phases[name] = phases[name] == null ? ms : lerp(phases[name], ms, .18);
    }

    function timeSimPhase(name, fn) {
      const t0 = performance.now();
      const result = fn();
      recordSimPhase(name, performance.now() - t0);
      return result;
    }

    function summarizeSimPhases() {
      const perf = game.performance;
      const phases = perf?.simPhases;
      if (!phases) return "";
      let first = null, second = null;
      for (const [name, ms] of Object.entries(phases)) {
        if (!Number.isFinite(ms) || ms < .05) continue;
        const item = { name, ms };
        if (!first || ms > first.ms) {
          second = first;
          first = item;
        } else if (!second || ms > second.ms) {
          second = item;
        }
      }
      const parts = [first, second].filter(Boolean).map((p) => `${p.name.toUpperCase()} ${p.ms.toFixed(1)}`);
      return parts.length ? `  SIM ${parts.join(" ")}` : "";
    }

    function viewCamera() {
      const cam = game.camera, mode = game.viewMode || "fwd";
      if (game.transition?.kind === "death") return externalViewCamera(cam);
      if (mode === "fwd" || game.docked) return cam;
      ensureCameraQuat(cam);
      if (mode === "ext") return externalViewCamera(cam);
      return { pos: cam.pos, q: quatNorm(quatMul(cam.q, quatFromAxisAngle(vec(0, 1, 0), VIEW_YAW[mode]))) };
    }

    function externalViewCamera(cam) {
      ensureCameraQuat(cam);
      // Chase position scales with the player's hull so a Worm and an Anaconda both frame nicely.
      const r = Math.max(60, modelBoundingRadius(MODELS[playerShipModel()]));
      const st = game.externalView || {};
      const yaw = st.yaw || 0;
      const pitch = clamp(st.pitch ?? Math.atan2(1.1, 3.4), -.95, 1.15);
      const zoom = clamp(st.zoom || 1, .42, 2.8);
      const dist = r * Math.hypot(3.4, 1.1) * zoom;
      const cp = Math.cos(pitch);
      const local = vec(
        Math.sin(yaw) * cp * dist,
        Math.sin(pitch) * dist,
        -Math.cos(yaw) * cp * dist
      );
      const pos = cameraLocalToWorld(cam, local);
      return {
        pos,
        q: quatLookRotation(norm(sub(cam.pos, pos)), quatRotate(cam.q, vec(0, 1, 0)))
      };
    }

    function transitionLocksView() {
      return !!game.transition || !!game.jumpCountdown;
    }

    function syncViewPresentation() {
      const mode = game.viewMode || "fwd";
      const cross = document.querySelector(".crosshair");
      const showReticle = mode === "fwd" && !game.docked && !transitionLocksView() && !game.playerDestroyed;
      if (cross) cross.style.display = showReticle ? "" : "none";
      if (space) space.style.cursor = mode === "ext" && !game.docked && !transitionLocksView() ? "grab" : "";
    }

    function forceTransitionViewMode() {
      game.viewMode = "fwd";
      syncViewPresentation();
    }

    function setViewMode(mode, opts = {}) {
      if (!(mode in VIEW_LABELS)) return false;
      if (!opts.force && transitionLocksView() && mode !== "fwd") {
        forceTransitionViewMode();
        if (!opts.silent) {
          const now = performance.now();
          if (!game._viewLockNoticeAt || now - game._viewLockNoticeAt > 900) {
            game._viewLockNoticeAt = now;
            setMessage("View locked during transition.", true);
          }
        }
        return false;
      }
      game.viewMode = mode;
      syncViewPresentation();
      return true;
    }

