    const FACE_RENDER_FACE_TEXTURE = 1;
    const FACE_RENDER_EXPLICIT_UV = 2;
    const FACE_RENDER_DECAL = 4;
    const FACE_RENDER_FALLBACK_COLOR = 8;
    const FACE_RENDER_MIRROR_X = 16;
    const FACE_RENDER_ANGLE = 32;
    const FACE_RENDER_SIDE = 64;

    function remapImageProjectionForBuiltFaces(data, entries) {
      const projection = data?.imageProjection;
      if (!projection || !Array.isArray(data?.faces) || !entries?.length) return projection || {};
      // buildBlueprint may rotate/reverse face vertices from the authored face order;
      // bitmap UVs must follow the rebuilt vertex order or textures land on wrong corners.
      const sourceFaces = data.faces.map((face) => Array.isArray(face)
        ? face
        : Array.isArray(face?.verts)
          ? face.verts
          : null);
      const hasSlot = (items, index) => Array.isArray(items) && Object.prototype.hasOwnProperty.call(items, index);
      const remapArrayByNormal = (field) => {
        const source = projection[field];
        if (!Array.isArray(source)) return null;
        return entries.map((entry) => hasSlot(source, entry.normalIndex) ? source[entry.normalIndex] : null);
      };
      const remapFaceUv = (entry) => {
        const sourceUv = hasSlot(projection.faceTextureUv, entry.normalIndex)
          ? projection.faceTextureUv[entry.normalIndex]
          : null;
        const sourceFace = sourceFaces[entry.normalIndex];
        if (!Array.isArray(sourceUv) || !Array.isArray(sourceFace) || sourceUv.length !== sourceFace.length) {
          return Array.isArray(sourceUv) && sourceUv.length === entry.face.length
            ? sourceUv.map((p) => Array.isArray(p) ? [Number(p[0]) || 0, Number(p[1]) || 0] : [0, 0])
            : null;
        }
        const uvByVertex = new Map();
        for (let i = 0; i < sourceFace.length; i++) uvByVertex.set(sourceFace[i], sourceUv[i]);
        const remapped = entry.face.map((vertexIndex) => uvByVertex.get(vertexIndex));
        return remapped.every((p) => Array.isArray(p))
          ? remapped.map((p) => [Number(p[0]) || 0, Number(p[1]) || 0])
          : null;
      };
      const remapped = { ...projection };
      for (const field of ["faceSides", "faceTextures", "faceTextureBaseW", "faceTextureBaseH", "faceTextureWrap", "faceColors", "faceAngles", "faceMirrorX", "faceDecals", "faceRenderFlags"]) {
        const values = remapArrayByNormal(field);
        if (values) remapped[field] = values;
      }
      if (Array.isArray(projection.faceTextureUv)) {
        remapped.faceTextureUv = entries.map(remapFaceUv);
      }
      return remapped;
    }

    function faceProjectionSlot(projection, field, faceIndex, normalIndex) {
      const items = projection?.[field];
      if (!Array.isArray(items)) return null;
      if (hasProjectionFaceSlot(items, faceIndex)) return items[faceIndex];
      return hasProjectionFaceSlot(items, normalIndex) ? items[normalIndex] : null;
    }

    function faceRenderFlagsFromProjection(projection, faceIndex, normalIndex) {
      const authored = faceProjectionSlot(projection, "faceRenderFlags", faceIndex, normalIndex);
      if (Number.isFinite(Number(authored))) return Number(authored) | 0;
      let flags = 0;
      const side = faceProjectionSlot(projection, "faceSides", faceIndex, normalIndex);
      const texture = faceProjectionSlot(projection, "faceTextures", faceIndex, normalIndex);
      const uv = faceProjectionSlot(projection, "faceTextureUv", faceIndex, normalIndex);
      const color = faceProjectionSlot(projection, "faceColors", faceIndex, normalIndex);
      const angle = faceProjectionSlot(projection, "faceAngles", faceIndex, normalIndex);
      const mirror = faceProjectionSlot(projection, "faceMirrorX", faceIndex, normalIndex);
      const decals = faceProjectionSlot(projection, "faceDecals", faceIndex, normalIndex);
      if (side) flags |= FACE_RENDER_SIDE;
      if (texture) flags |= FACE_RENDER_FACE_TEXTURE;
      if (Array.isArray(uv) && uv.length >= 3) flags |= FACE_RENDER_EXPLICIT_UV;
      if (/^#[0-9a-f]{6}$/i.test(String(color || ""))) flags |= FACE_RENDER_FALLBACK_COLOR;
      if (Number.isFinite(Number(angle)) && Math.abs(Number(angle)) > .0001) flags |= FACE_RENDER_ANGLE;
      if (mirror) flags |= FACE_RENDER_MIRROR_X;
      if (Array.isArray(decals) && decals.length) flags |= FACE_RENDER_DECAL;
      return flags;
    }

    function faceBaseColorFromProjection(projection, faceIndex, normalIndex) {
      const color = faceProjectionSlot(projection, "faceColors", faceIndex, normalIndex);
      return /^#[0-9a-f]{6}$/i.test(String(color || "")) ? color : null;
    }

    function detailRenderIntent(detail) {
      const type = detail?.type === "panel" ? "line" : detail?.type;
      const line = type === "line" || type === "polyline";
      const beacon = type === "beacon";
      const engine = type === "engine";
      const window = type === "window";
      const stationEntrance = type === "stationEntrance";
      return {
        kind: stationEntrance ? "stationEntrance" : beacon ? "beacon" : line ? "line" : "poly",
        solid: !line && !stationEntrance,
        wire: !beacon,
        glow: engine,
        glass: window,
        solidStroke: engine
      };
    }

    function buildBlueprint(data) {
      const model = { ...data };
      model.details = (model.details || []).map((detail) => ({
        ...detail,
        detailRender: detail.detailRender || detailRenderIntent(detail)
      }));
      const faceEntries = model.normals.map((normal, faceIndex) => {
        const ids = new Set();
        model.edges.forEach((edge, edgeIndex) => {
          const ef = model.edgeFaces[edgeIndex];
          if (ef[0] === ef[1]) return;
          if (ef.includes(faceIndex)) {
            ids.add(edge[0]);
            ids.add(edge[1]);
          }
        });
        if (ids.size < 3) return null;
        const n = norm(vec(normal[0], normal[1], normal[2]));
        const center = [...ids].reduce((sum, i) => add(sum, vec(...model.verts[i])), vec());
        const c = scale(center, 1 / ids.size);
        let axis = cross(n, Math.abs(n.y) < .9 ? vec(0, 1, 0) : vec(1, 0, 0));
        if (len(axis) < .0001) axis = cross(n, vec(0, 0, 1));
        const u = norm(axis);
        const v = norm(cross(n, u));
        const face = [...ids].sort((a, b) => {
          const pa = sub(vec(...model.verts[a]), c);
          const pb = sub(vec(...model.verts[b]), c);
          return Math.atan2(dot(pa, v), dot(pa, u)) - Math.atan2(dot(pb, v), dot(pb, u));
        });
        if (face.length >= 3) {
          const calc = faceNormal(vec(...model.verts[face[0]]), vec(...model.verts[face[1]]), vec(...model.verts[face[2]]));
          if (dot(calc, n) < 0) face.reverse();
        }
        // UV is derived from the object-local (unrotated) vertex positions, so it's
        // fixed per face and stays glued to the surface as the object rotates on screen.
        const uv = face.map((i) => {
          const p = sub(vec(...model.verts[i]), c);
          return [dot(p, u), dot(p, v)];
        });
        return { face, uv, normalIndex: faceIndex };
      });
      const entries = faceEntries.filter(Boolean);
      const duplicateFaceKeys = new Set();
      const faceKeyMap = new Map();
      for (const entry of entries) {
        const key = [...entry.face].sort((a, b) => a - b).join(",");
        if (!faceKeyMap.has(key)) faceKeyMap.set(key, []);
        faceKeyMap.get(key).push(entry);
      }
      for (const group of faceKeyMap.values()) {
        if (group.length < 2) continue;
        for (let i = 0; i < group.length; i++) {
          for (let j = i + 1; j < group.length; j++) {
            const a = norm(vec(...model.normals[group[i].normalIndex]));
            const b = norm(vec(...model.normals[group[j].normalIndex]));
            if (dot(a, b) < -.85) {
              duplicateFaceKeys.add(group[i].normalIndex);
              duplicateFaceKeys.add(group[j].normalIndex);
            }
          }
        }
      }
      model.faceByNormalIndex = faceEntries.map((entry) => entry ? entry.face : null);
      model.faceUVByNormalIndex = faceEntries.map((entry) => entry ? entry.uv : null);
      model.faces = entries.map((e) => e.face);
      model.faceUV = entries.map((e) => e.uv);
      model.faceNormalIndices = entries.map((e) => e.normalIndex);
      model.wireMaskFaces = entries.map((e) => duplicateFaceKeys.has(e.normalIndex) ? 0 : 1);
      model.imageProjection = remapImageProjectionForBuiltFaces(data, entries);
      model.faceRenderFlags = entries.map((entry, faceIndex) =>
        faceRenderFlagsFromProjection(model.imageProjection, faceIndex, entry.normalIndex));
      model.faceBaseColors = entries.map((entry, faceIndex) =>
        faceBaseColorFromProjection(model.imageProjection, faceIndex, entry.normalIndex));
      model.wireCullEdgeKeys = new Set(Object.keys(model.edgeCullNormals || {}).map((edgeIndex) => {
        const edge = model.edges[Number(edgeIndex)];
        return edge ? (edge[0] < edge[1] ? `${edge[0]},${edge[1]}` : `${edge[1]},${edge[0]}`) : "";
      }).filter(Boolean));
      model.decalUV = buildContinuousDecalUV(model.verts, model.faces);
      model.imageProjectionUV = buildProjectedImageDecalUV(model.verts, model.faces, model.faceNormalIndices, model.normals, model.imageProjection || {});
      return model;
    }

