    function setDomText(el, value) {
      const text = String(value);
      if (el && el.textContent !== text) el.textContent = text;
    }

    function setDomHidden(el, value) {
      if (el && el.hidden !== value) el.hidden = value;
    }

    function setDomDisabled(el, value) {
      if (el && el.disabled !== value) el.disabled = value;
    }

    function setDomAttr(el, name, value) {
      const text = String(value);
      if (el && el.getAttribute(name) !== text) el.setAttribute(name, text);
    }

    function setStyleProp(el, prop, value) {
      if (el && el.style[prop] !== value) el.style[prop] = value;
    }

    function updatePauseHud() {
      setDomText(hudEls.pauseValue, game.paused ? "PAUSED" : "RUN");
      setDomAttr(hudEls.pauseBtn, "aria-pressed", game.paused ? "true" : "false");
      setDomAttr(hudEls.pauseBtn, "aria-label", game.paused ? "Resume game" : "Pause game");
      setDomHidden(hudEls.pauseBtn, false);
    }

    function updateVolumeHud() {
      const pct = Math.round(normalizeAudioVolume(game.audioVolume) * 100);
      if (hudEls.volumeSlider && hudEls.volumeSlider.value !== String(pct)) hudEls.volumeSlider.value = String(pct);
      setDomText(hudEls.volumeValue, pct);
      setDomAttr(hudEls.volumeControl, "data-volume-state", pct <= 0 ? "muted" : pct < 35 ? "low" : "normal");
      setDomHidden(hudEls.volumeControl, false);
    }

    function updateBrightnessHud() {
      const level = normalizeVisualBrightness(game.visualBrightness);
      const pct = Math.round(level * 100);
      if (space) space.style.setProperty("--visual-brightness", String(level));
      if (hudEls.brightnessSlider && hudEls.brightnessSlider.value !== String(pct)) hudEls.brightnessSlider.value = String(pct);
      setDomText(hudEls.brightnessValue, pct);
      setDomAttr(hudEls.brightnessControl, "data-brightness-state", pct < 92 ? "dim" : pct > 108 ? "bright" : "normal");
      setDomHidden(hudEls.brightnessControl, false);
    }

    function updatePerformanceTickerHud() {
      const perf = game.performance;
      if (!hudEls.perfTicker || !perf) return;
      const fps = Math.round(1000 / Math.max(1, perf.frameMs || 16.7));
      const label = perf.qualityLabel || PERFORMANCE_LOD_LABELS[perf.lod || 0] || "HIGH";
      setDomText(hudEls.perfTicker, `FPS ${fps}  AUTO ${label}  LOD ${perf.lod || 0}  OBJ ${perf.visibleModels || 0}${summarizeSimPhases()}`);
      setDomAttr(hudEls.perfTicker, "data-load", (perf.lod || 0) >= 2 ? "high" : "normal");
      setDomHidden(hudEls.perfTicker, false);
    }

    function setBootProgress(percent, text = "") {
      game.bootProgress = clamp(Number(percent) || 0, 0, 100);
      const rounded = Math.round(game.bootProgress);
      const fill = byId("splashLoadingFill");
      const pct = byId("splashLoadingPct");
      const label = byId("splashLoadingText");
      if (fill) fill.style.width = `${rounded}%`;
      if (pct) pct.textContent = `${rounded}%`;
      if (label && text) label.textContent = text;
    }

    function markBootReady() {
      game.bootReady = true;
      setBootProgress(100, "READY");
      const splashEl = byId("splash");
      const prompt = byId("splashPrompt");
      if (splashEl) splashEl.classList.add("ready");
      if (prompt) prompt.textContent = "PRESS ANY KEY TO START";
      updateReadouts();
    }

    function nextBootFrame() {
      return new Promise((resolve) => requestAnimationFrame(() => resolve()));
    }

    function toggleClass(el, name, value) {
      if (el && el.classList.contains(name) !== value) el.classList.toggle(name, value);
    }

    function currentSystem() {
      return galaxies[game.galaxy][game.current];
    }

    function targetSystem() {
      return galaxies[game.galaxy][game.target];
    }

    function finalTargetSystem() {
      const maxSystem = galaxies[game.galaxy].length - 1;
      if (!Number.isInteger(game.finalTarget)) game.finalTarget = game.target;
      const raw = Number.isFinite(Number(game.finalTarget))
        ? Number(game.finalTarget)
        : Number.isFinite(Number(game.target)) ? Number(game.target) : DISO_INDEX;
      game.finalTarget = clamp(Math.trunc(raw), 0, maxSystem);
      return galaxies[game.galaxy][game.finalTarget];
    }

    function distance(a, b) {
      return Math.hypot(a.x - b.x, a.y - b.y) / 4;
    }

    function currentHyperdriveRangeLy() {
      return 7;
    }

    function fuelTankCapacityLy() {
      return 7;
    }

    function usedCargo() {
      return Object.values(game.cargo || {}).reduce((a, b) => a + Math.max(0, Math.trunc(Number(b) || 0)), 0) + missionCargoUsed();
    }

    function cargoFuelTons() {
      return Math.max(0, Math.trunc(Number(game.cargo?.[CARGO_FUEL_GOOD]) || 0));
    }

    function loadFuelFromCargo() {
      const available = cargoFuelTons();
      if (!available || game.fuel >= fuelTankCapacityLy() - .0001) return { loadedLy: 0, tons: 0 };
      const neededLy = fuelTankCapacityLy() - game.fuel;
      const tons = Math.min(available, Math.ceil(neededLy / CARGO_FUEL_LY_PER_TON));
      const loadedLy = Math.min(neededLy, tons * CARGO_FUEL_LY_PER_TON);
      game.cargo[CARGO_FUEL_GOOD] = available - tons;
      game.fuel = clamp(game.fuel + loadedLy, 0, fuelTankCapacityLy());
      return { loadedLy, tons };
    }

    function refuelFromCargoStatus() {
      if (!game.equipment.cargoRefuel) {
        eliteAudio.play("boop");
        setMessage("Cargo Refueler not fitted.");
        renderPanel();
        return;
      }
      if (game.fuel >= fuelTankCapacityLy() - .0001) {
        eliteAudio.play("boop");
        setMessage("Fuel tanks already full.");
        renderPanel();
        return;
      }
      if (!cargoFuelTons()) {
        eliteAudio.play("boop");
        setMessage("No Fuel Cells in cargo.");
        renderPanel();
        return;
      }
      const loaded = loadFuelFromCargo();
      eliteAudio.play("scoop");
      setMessage(`Cargo fuel loaded ${fmt(loaded.loadedLy)} LY from ${loaded.tons}t Fuel Cells.`, true);
      renderPanel();
    }

    function rankName() {
      let r = RANKS[0][0];
      const score = game.kills + (Number(game.missionRankPoints) || 0);
      for (const [name, min] of RANKS) if (score >= min) r = name;
      return r;
    }

    function legalStatus() {
      if (game.legal <= 0) return "CLEAN";
      if (game.legal < 16) return "OFFENDER";
      return "FUGITIVE";
    }

    function laserPower() {
      const shotHeat = 8; // BBC Elite's LASLI adds the same gun heat per actual firing event.
      if (missionLoanActive("navalOverchargeLaser")) return {
        id: "navalOvercharge", name: "Naval Overcharge", damage: 19, heat: shotHeat + 3, range: 5200,
        cooldown: 64, duration: 105, width: 3.4, color: "#c8f6ff", sound: "laserMilitary"
      };
      if (game.equipment.militaryLaser) return {
        id: "military", name: "Military", damage: 14, heat: shotHeat, range: 4600,
        cooldown: 72, duration: 95, width: 2.8, color: "#8fe8ff", sound: "laserMilitary"
      };
      if (game.equipment.beamLaser) return {
        id: "beam", name: "Beam", damage: 9, heat: shotHeat, range: 3400,
        cooldown: 72, duration: 135, width: 2.1, color: "#ffd33d", sound: "laserBeam"
      };
      if (game.equipment.miningLaser) return {
        id: "mining", name: "Mining", damage: 18, rockMul: 3, heat: shotHeat, range: 1700,
        cooldown: 1000, duration: 230, width: 4.6, color: "#e8f2e4", sound: "laserMining"
      };
      return {
        id: "pulse", name: "Pulse", damage: 16, heat: shotHeat, range: 2400,
        cooldown: 200, duration: 125, width: 2.4, color: "#ff6a55", sound: "laserPulse"
      };
    }

    const LASER_EQUIPMENT_IDS = ["miningLaser", "beamLaser", "militaryLaser"];
    const DEV_EQUIPMENT_ORDER = {
      miningLaser: 10,
      beamLaser: 11,
      militaryLaser: 12
    };

    function isLaserEquipment(id) {
      return LASER_EQUIPMENT_IDS.includes(id);
    }

    function fitLaser(id) {
      for (const laserId of LASER_EQUIPMENT_IDS) game.equipment[laserId] = laserId === id;
    }

    function normalizeLaserFit() {
      const active = ["militaryLaser", "beamLaser", "miningLaser"].find((id) => game.equipment[id]);
      if (active) fitLaser(active);
    }

    function normalizeCommanderName(name) {
      const clean = String(name || "")
        .toUpperCase()
        .replace(/[^A-Z0-9 ]/g, "")
        .replace(/\s+/g, " ")
        .trim()
        .slice(0, 7);
      return clean || "JAMESON";
    }

    function currentFullscreenElement() {
      return document.fullscreenElement || document.webkitFullscreenElement || null;
    }

    const SAFARI_FULLSCREEN_KEY_GUARD = typeof navigator !== "undefined"
      && /^((?!chrome|android).)*safari/i.test(navigator.userAgent || "");
    const SAFARI_CANVAS_COMPOSITE_GUARD = SAFARI_FULLSCREEN_KEY_GUARD;

    function requestGameFullscreen(pointerGesture = false) {
      if (SAFARI_FULLSCREEN_KEY_GUARD && !pointerGesture) return;
      if (currentFullscreenElement()) return;
      const root = document.documentElement;
      try {
        const request = root.requestFullscreen
          ? root.requestFullscreen({ navigationUI: "hide" })
          : root.webkitRequestFullscreen
            ? root.webkitRequestFullscreen()
            : null;
        if (request?.catch) request.catch(() => {});
      } catch (_) {}
    }

    let commanderNameDialogOpen = false;
    let commanderNameDialogForce = false;
    let missionCompleteDialogOpen = false;
    const missionCompleteQueue = [];

    function setCommanderNameDialog(open, force = false) {
      const dialog = byId("commanderNameDialog");
      const input = byId("commanderNameInput");
      if (!dialog || !input) return false;
      commanderNameDialogOpen = open;
      commanderNameDialogForce = force;
      setDomHidden(dialog, !open);
      if (open) {
        const current = normalizeCommanderName(game.commander);
        input.value = current;
        const cancel = byId("commanderNameCancel");
        if (cancel) cancel.textContent = current === "JAMESON" && !force ? "Use Jameson" : "Cancel";
        setTimeout(() => {
          input.focus({ preventScroll: true });
          input.select();
        }, 0);
      }
      return true;
    }

    function submitCommanderNameDialog(useCurrent = false, pointerGesture = false) {
      const input = byId("commanderNameInput");
      const current = normalizeCommanderName(game.commander);
      game.commander = normalizeCommanderName(useCurrent ? current : (input?.value || current));
      const poopyCommander = game.commander === "POOPY";
      const poopyBonus = poopyCommander && !game.poopyBonusClaimed;
      const poopyComparatorGift = poopyCommander && !game.equipment.marketComparator;
      const poopyCargoRefuelGift = poopyCommander && !game.equipment.cargoRefuel;
      const danstoDevUnlock = game.commander === "DANSTO" && !game.developerMode;
      if (poopyBonus) {
        game.poopyBonusClaimed = true;
        game.credits += 1000;
      }
      if (poopyComparatorGift) game.equipment.marketComparator = true;
      if (poopyCargoRefuelGift) game.equipment.cargoRefuel = true;
      if (danstoDevUnlock) launchDevMode();
      setCommanderNameDialog(false);
      requestGameFullscreen(pointerGesture);
      setMessage(danstoDevUnlock
        ? "Commander DANSTO registered. Launch Dev Mode enabled."
        : poopyBonus || poopyComparatorGift || poopyCargoRefuelGift
          ? `Commander POOPY registered.${poopyBonus ? " 1000 CR bonus awarded." : ""}${poopyComparatorGift ? " Market Comparator fitted." : ""}${poopyCargoRefuelGift ? " Cargo Refueler fitted." : ""}`
          : `Commander registered: ${game.commander}.`, true);
      renderPanel();
      updateReadouts();
      return true;
    }

    function cancelCommanderNameDialog() {
      if (commanderNameDialogForce) return submitCommanderNameDialog(true, false);
      setCommanderNameDialog(false);
      return false;
    }

    function askCommanderName(force = false) {
      return setCommanderNameDialog(true, force);
    }

    function missionCompleteDialogPayload(mission) {
      return {
        title: mission?.title || "Mission complete",
        body: mission?.completionMessage || "Mission complete. Your account has been credited.",
        issuer: mission?.issuer || "Mission Office",
        destination: mission?.destination?.name || currentSystem().name,
        reward: missionRewardText(mission),
        queueRemaining: 0
      };
    }

    function showNextMissionCompleteDialog() {
      if (missionCompleteDialogOpen) return;
      const next = missionCompleteQueue.shift();
      const dialog = byId("missionCompleteDialog");
      if (!dialog || !next) {
        missionCompleteDialogOpen = false;
        if (dialog) setDomHidden(dialog, true);
        return;
      }
      next.queueRemaining = missionCompleteQueue.length;
      setDomText(byId("missionCompleteName"), next.title);
      setDomText(byId("missionCompleteBody"), next.body);
      setDomText(byId("missionCompleteIssuer"), next.issuer);
      setDomText(byId("missionCompleteDestination"), next.destination);
      setDomText(byId("missionCompleteReward"), next.reward);
      setDomText(byId("missionCompletePrompt"), next.queueRemaining
        ? `Press Space for next completion (${next.queueRemaining} waiting)`
        : "Press Space to dismiss");
      missionCompleteDialogOpen = true;
      setDomHidden(dialog, false);
      setTimeout(() => byId("missionCompleteDismiss")?.focus({ preventScroll: true }), 0);
    }

    function queueMissionCompleteDialogs(completed) {
      const payloads = (completed || []).map(missionCompleteDialogPayload);
      if (!payloads.length) return;
      missionCompleteQueue.push(...payloads);
      showNextMissionCompleteDialog();
    }

    function dismissMissionCompleteDialog() {
      const dialog = byId("missionCompleteDialog");
      if (!missionCompleteDialogOpen) return false;
      missionCompleteDialogOpen = false;
      if (dialog) setDomHidden(dialog, true);
      setTimeout(showNextMissionCompleteDialog, 80);
      return true;
    }

    function baseMarketFor(system) {
      return GOODS.map(([name, basePrice, factor, baseQty, mask, unit, illegal]) => {
        const swing = system.marketRand & mask;
        const price = Math.max(1, (basePrice + swing + system.economy * factor) * 0.4);
        const raw = baseQty + swing - system.economy * factor;
        const qty = clamp(raw & 63, 0, 63);
        return { name, price, qty, unit, illegal };
      });
    }

    function marketStockKey(system) {
      const systemIndex = Number.isFinite(system?.index) ? system.index : game.current;
      return `${game.galaxy}:${systemIndex}`;
    }

    function marketStockFor(system) {
      if (!game.marketStock || typeof game.marketStock !== "object") game.marketStock = {};
      const key = marketStockKey(system);
      if (!game.marketStock[key]) {
        game.marketStock[key] = Object.fromEntries(baseMarketFor(system).map((item) => [item.name, item.qty]));
      }
      return game.marketStock[key];
    }

    function marketFor(system) {
      const stock = marketStockFor(system);
      return baseMarketFor(system).map((item) => ({
        ...item,
        qty: Math.max(0, Math.trunc(Number(stock[item.name] ?? item.qty) || 0))
      }));
    }

    function marketComparatorForDestination() {
      if (!game.equipment.marketComparator) return null;
      const current = currentSystem();
      const dest = finalTargetSystem();
      if (!dest || dest.index === current.index) return { system: dest || current, prices: new Map(), active: false };
      const prices = new Map(baseMarketFor(dest).map((item) => [item.name, item.price]));
      return { system: dest, prices, active: true };
    }

    function canUseMarket() {
      return !!game.docked && !game.transition && !game.jumpCountdown && !game.playerDestroyed;
    }

    // --- NPC comms chatter -------------------------------------------------------
    // Situation-driven one-liners from live ships, shown in a small fading log on the
    // flight view. Same panel is the natural home for player chat if multiplayer lands.
    const HACK_DISABLE_CHATTER = false;
    const escapeHtml = (s) => String(s).replace(/[&<>]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
    const escapeAttr = (s) => escapeHtml(s).replace(/"/g, "&quot;");
    const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];

    const MISSION_MAX_ACTIVE = 8;
    const MISSION_BOARD_MIN = 2;
    const MISSION_BOARD_MAX = 10;
    const MISSION_NPC_DEFINITIONS = globalThis.ULTRA_ELITE_MISSION_NPC_DEFINITIONS || { missionTypes: {}, npcBehaviours: {} };
    const MISSION_DEFINITIONS = MISSION_NPC_DEFINITIONS.missionTypes || {};
    const MISSION_TYPES = Object.fromEntries(Object.entries(MISSION_DEFINITIONS).map(([id, def]) => [id, def.label || id]));
    const NAVAL_BATTLE_REP_UNLOCK = 4;
    const MISSION_CONTRACT_ITEMS = [
      "prototype flight computer", "experimental ship drive", "military targeting core",
      "corporate data vault", "biotech sample pod", "classified survey recorder",
      "quantum fuel regulator", "Sirius personality module", "encrypted navigation wafer",
      "sealed alloy sample"
    ];
    const MISSION_STARTER_ITEMS = [
      "station mailbag", "medical paperwork", "replacement circuit boards",
      "seed samples", "docking clamp spares", "trade invoices",
      "survey notes", "navigation almanac", "harmless specimen case"
    ];
    const MISSION_RECOVERY_ITEMS = [
      "stolen prototype computer", "naval flight recorder", "alien alloy panel",
      "corporate cipher module", "black box recorder", "experimental guidance core"
    ];
    const MISSION_ISSUERS = {
      courier: ["Lloyd's Interstellar", "GalCop Dispatch", "Free Traders' Exchange", "Station Records Office"],
      cargo: ["Sirius Cybernetics", "Zieman Logistics", "Wiccan Warehousing", "Orbital Materials Trust"],
      bounty: ["GalCop Warrants", "Station Security", "Pilot's Protective Guild", "Local Justice Office"],
      suppression: ["Station Security", "GalCop Patrol Liaison", "Local Defence Office", "Trade Lane Authority"],
      recovery: ["Sirius Recovery Bureau", "Tionisla Data Factors", "Corporate Salvage Board", "Insurance Underwriters"],
      naval: ["GalCop Naval Intelligence", "Sector Naval Command", "Federal Liaison Office", "Joint Xeno Desk"],
      traderDefence: ["Free Traders' Exchange", "Trade Lane Authority", "Pilot's Protective Guild", "Local Convoy Office"],
      navalBattle: ["GalCop Naval Intelligence", "Sector Naval Command", "Federal Liaison Office", "Joint Xeno Desk"]
    };
    const MISSION_TARGET_NAMES = [
      "BLACK ACRE", "MORNING KNIFE", "RED LEDGER", "NULL SAINT", "STATIC REEF",
      "BONE MARKET", "COLD VECTOR", "GRIEF ENGINE", "VANTA WAKE", "SILENT FEE"
    ];
    const NAVAL_LOAN_SHIPS = ["naga", "umbra"];
    const DEV_MISSION_PRESETS = [
      { id: "starterCourier", label: "Starter Courier", type: "courier", opts: { starter: true, rewardCredits: 65, rankPoints: 1, titlePrefix: "Dev starter courier" } },
      { id: "starterFreight", label: "Starter Freight", type: "cargo", opts: { starter: true, cargoItem: "station mailbag", rewardCredits: 75, rankPoints: 1, titlePrefix: "Dev starter freight" } },
      { id: "privateBounty", label: "Private Bounty", type: "bounty", opts: { heat: 2, legalClass: "private", targetModel: "mamba", rewardCredits: 520, rankPoints: 2 } },
      { id: "pirateSuppression", label: "Pirate Sweep", type: "suppression", opts: { heat: 2, legalClass: "sanctioned", suppressionKills: 4, rewardCredits: 860, rankPoints: 2 } },
      { id: "sanctionedRecovery", label: "Recovery", type: "recovery", opts: { heat: 3, legalClass: "sanctioned", targetModel: "krait", recoveryName: "stolen prototype computer", rewardCredits: 790, rankPoints: 2 } },
      { id: "thargoidNaval", label: "Thargoid Naval", type: "naval", opts: { heat: 4, legalClass: "military", targetModel: "thargoid", recoveryName: "alien alloy panel", loanShip: "naga", loan: { id: "navalEcm", name: "Long-range Naval ECM", keepChance: 0 }, rewardCredits: 1250, rankPoints: 5, noRandomSpecialRewards: true } },
      { id: "traderDefence", label: "Trader Defence", type: "traderDefence", opts: { heat: 3, legalClass: "sanctioned", encounterRequired: 3, rewardCredits: 980, rankPoints: 3 } },
      { id: "navalBattle", label: "Naval Battle", type: "navalBattle", opts: { heat: 4, legalClass: "military", encounterRequired: 3, navalReputationRequired: 0, rewardCredits: 1650, rankPoints: 5, navalReputation: 4 } },
      { id: "loanLaser", label: "Loan Laser", type: "naval", opts: { heat: 4, legalClass: "military", targetModel: "asp", loanShip: "naga", loan: { id: "navalOverchargeLaser", name: "Overcharged Naval Laser", keepChance: 0 }, rewardCredits: 1100, rankPoints: 4, noRandomSpecialRewards: true } },
      { id: "keepLaser", label: "Keep Laser", type: "naval", opts: { heat: 4, legalClass: "military", targetModel: "ferdelance", loanShip: "umbra", loan: { id: "navalOverchargeLaser", name: "Overcharged Naval Laser", keepChance: 1 }, rewardEquipment: "militaryLaser", rewardCredits: 1450, rankPoints: 5, noRandomSpecialRewards: true } },
      { id: "shipReward", label: "Keep Ship", type: "naval", opts: { heat: 4, legalClass: "military", targetModel: "constrictor", loan: { id: "navalEcm", name: "Long-range Naval ECM", keepChance: 0 }, rewardShip: "umbra", rewardCredits: 2200, rankPoints: 6, noRandomSpecialRewards: true } },
      { id: "specialCargo", label: "Special Cargo", type: "cargo", opts: { heat: 3, legalClass: "sanctioned", destinationBands: [[28, 44], [18, 36], [8, 24]], cargoItem: "experimental ship drive", cargoTons: 1, cargoSecret: true, rewardEquipment: "militaryLaser", rewardCredits: 1750, rankPoints: 3 } }
    ];

    function missionState() {
      if (!game.missions || typeof game.missions !== "object") game.missions = {};
      if (!Array.isArray(game.missions.active)) game.missions.active = [];
      if (!Array.isArray(game.missions.board)) game.missions.board = [];
      if (!Number.isFinite(game.missions.dockSerial)) game.missions.dockSerial = 0;
      if (!Number.isFinite(game.missions.completed)) game.missions.completed = 0;
      if (!game.missionUnlocks || typeof game.missionUnlocks !== "object") game.missionUnlocks = { ships: [] };
      if (!Array.isArray(game.missionUnlocks.ships)) game.missionUnlocks.ships = [];
      if (!Array.isArray(game.missionUnlocks.ownedShips)) game.missionUnlocks.ownedShips = [playerShipModel()];
      if (!game.missionUnlocks.ownedShips.includes(playerShipModel())) game.missionUnlocks.ownedShips.push(playerShipModel());
      return game.missions;
    }

    function systemRef(system = currentSystem()) {
      return { galaxy: system.galaxy ?? game.galaxy, system: system.index, name: system.name };
    }

    function sameSystemRef(ref, system = currentSystem()) {
      return !!ref && ref.galaxy === (system.galaxy ?? game.galaxy) && ref.system === system.index;
    }

    function missionCargoUsed() {
      const state = missionState();
      return state.active.reduce((sum, mission) => {
        if (mission.status !== "active") return sum;
        const sealed = mission.cargo?.held ? Number(mission.cargo.tons) || 0 : 0;
        const recovered = mission.recovery?.held ? Number(mission.recovery.tons) || 0 : 0;
        return sum + sealed + recovered;
      }, 0);
    }

    function isMissionCargoObject(o) {
      return !!o?.missionCargo;
    }

    function activeMissionById(id) {
      return missionState().active.find((mission) => mission.id === id && mission.status === "active") || null;
    }

    function missionHasLoanerShip(mission) {
      return !!mission?.loanShip?.model && !mission.loanShip.keep;
    }

    function activeImmediateDispatchMission() {
      return missionState().active.find((mission) =>
        mission.status === "active"
        && missionHasLoanerShip(mission)
      ) || null;
    }

    function immediateDispatchMissionForCourse() {
      const mission = activeImmediateDispatchMission();
      return mission?.destination?.galaxy === game.galaxy && Number.isInteger(mission.destination.system)
        ? mission
        : null;
    }

    function syncImmediateDispatchCourse({ announce = false } = {}) {
      const mission = immediateDispatchMissionForCourse();
      if (!mission) return null;
      if (game.finalTarget !== mission.destination.system) {
        const routeState = setFinalDestination(mission.destination.system);
        if (announce) {
          const hop = routeState.next && routeState.next.index !== game.finalTarget ? ` Next jump: ${routeState.next.name}.` : "";
          setMessage(`Immediate dispatch course locked: ${mission.destination.name}.${hop}`, true);
        }
      } else {
        updateNextDestinationForFinalTarget();
      }
      return mission;
    }

    function clearImmediateDispatchCourse(mission) {
      if (!mission?.destination || mission.destination.galaxy !== game.galaxy) return;
      if (game.finalTarget === mission.destination.system) setFinalDestination(game.current);
    }

    function missionLockedOutOnChart(mission) {
      const dispatch = activeImmediateDispatchMission();
      return !!dispatch && !!mission && mission.id !== dispatch.id;
    }

    function missionProgressUnlocked(mission) {
      if (!mission || mission.status !== "active") return false;
      const dispatch = activeImmediateDispatchMission();
      return !dispatch || dispatch.id === mission.id;
    }

    function missionChoice(rng, list) {
      return list[Math.floor(rng() * list.length) % list.length];
    }

    function missionRatingScore() {
      return (Number(game.kills) || 0) + (Number(game.missionRankPoints) || 0);
    }

    function navalReputationScore() {
      return Number(game.navalReputation) || 0;
    }

    function systemsInRange(from, minLy, maxLy) {
      return galaxies[from.galaxy ?? game.galaxy]
        .filter((system) => system.index !== from.index)
        .map((system) => ({ system, d: distance(from, system) }))
        .filter((entry) => entry.d >= minLy && entry.d <= maxLy)
        .sort((a, b) => a.d - b.d);
    }

    function missionDestination(rng, from, type, opts = {}) {
      const bands = Array.isArray(opts.destinationBands) && opts.destinationBands.length
        ? opts.destinationBands
        : opts.starter
        ? [[1, 7], [1, 10], [1, 14]]
        : type === "naval" || type === "navalBattle"
        ? [[18, 64], [8, 42], [4, 28]]
        : type === "suppression" || type === "traderDefence"
          ? [[3, 18], [1, 12], [18, 34]]
        : type === "courier"
          ? [[4, 14], [14, 30], [1, 8]]
          : [[7, 34], [2, 16], [20, 42]];
      for (const [minLy, maxLy] of bands) {
        const candidates = systemsInRange(from, minLy, maxLy);
        if (candidates.length) return missionChoice(rng, candidates).system;
      }
      return missionChoice(rng, galaxies[from.galaxy ?? game.galaxy].filter((s) => s.index !== from.index)) || from;
    }

    function missionRewardBase(type, dist, rng, heat = 0, opts = {}) {
      if (opts.starter) return Math.round((35 + dist * 8 + rng() * 45) / 5) * 5;
      const base = {
        courier: 90,
        cargo: 145,
        bounty: 320,
        suppression: 300,
        recovery: 430,
        naval: 620,
        traderDefence: 380,
        navalBattle: 760
      }[type] || 120;
      return Math.round((base + dist * (type === "courier" ? 18 : type === "naval" || type === "navalBattle" ? 48 : 32) + heat * 120 + rng() * base) / 5) * 5;
    }

    function missionRequirementsFor(type, dist, heat, mission = null) {
      const requirements = [];
      const addReq = (id, label, extra = {}) => {
        if (!requirements.some((req) => req.id === id)) requirements.push({ id, label, ...extra });
      };
      if (dist > 18 || heat >= 3) addReq("fuelScoop", "Fuel Scoop");
      if (type === "recovery" || type === "naval" || type === "navalBattle") addReq("fuelScoop", "Fuel Scoop");
      if ((type === "bounty" || type === "recovery" || type === "suppression" || type === "traderDefence") && heat >= 2) addReq("upgradedLaser", "Beam, mining or military laser");
      if ((type === "naval" || type === "navalBattle") && mission?.loan?.id !== "navalOverchargeLaser") addReq("upgradedLaser", "Beam, mining or military laser");
      if (type === "naval" || type === "navalBattle" || heat >= 4 || (type === "suppression" && heat >= 3)) addReq("extraEnergy", "Extra Energy Unit");
      if (heat >= 3 && type === "cargo") addReq("ecm", "E.C.M. System");
      const navalRepRequired = Number(mission?.encounter?.navalReputationRequired) || 0;
      if (type === "navalBattle" && navalRepRequired > 0) addReq("navalReputation", `Naval reputation ${navalRepRequired}+`, { min: navalRepRequired });
      return requirements;
    }

    function missionRequirementMet(req, mission = null) {
      if (!req) return true;
      if (devBypassesMissionRequirements()) return true;
      if (req.id === "upgradedLaser") return !!(game.equipment.beamLaser || game.equipment.miningLaser || game.equipment.militaryLaser || mission?.loan?.id === "navalOverchargeLaser");
      if (req.id === "ecm") return !!(game.equipment.ecm || mission?.loan?.id === "navalEcm");
      if (req.id === "navalReputation") return navalReputationScore() >= (Number(req.min) || NAVAL_BATTLE_REP_UNLOCK);
      return !!game.equipment[req.id];
    }

    function devBypassesMissionRequirements() {
      return !!game.developerMode;
    }

    function missingMissionRequirements(mission) {
      return (mission?.requirements || []).filter((req) => !missionRequirementMet(req, mission));
    }

    function missionTargetModel(rng, type) {
      if (type === "naval" || type === "navalBattle") return rng() < .72 ? "thargoid" : missionChoice(rng, ["constrictor", "asp", "ferdelance"]);
      if (type === "recovery") return missionChoice(rng, ["krait", "mamba", "asp", "ferdelance", "constrictor"]);
      return missionChoice(rng, ["sidewinder", "mamba", "krait", "gecko", "adder", "cobra"]);
    }

    function navalLoanShipModel(rng, heat, opts = {}) {
      if (opts.noLoanShip) return "";
      if (opts.loanShip && isDockyardShipModel(opts.loanShip)) return opts.loanShip;
      if (opts.rewardShip && isDockyardShipModel(opts.rewardShip)) return opts.rewardShip;
      const candidates = NAVAL_LOAN_SHIPS.filter(isDockyardShipModel);
      if (!candidates.length) return "";
      if (heat >= 4 && candidates.includes("umbra") && rng() < .42) return "umbra";
      return candidates.includes("naga") ? "naga" : candidates[0];
    }

    function missionLegalClass(type, rng) {
      if (type === "naval" || type === "navalBattle") return "military";
      if (type === "suppression" || type === "traderDefence") return "sanctioned";
      const sys = currentSystem();
      const anarchyBias = clamp((3 - sys.government) / 4, 0, .45);
      if (type === "bounty" && rng() < .14 + anarchyBias) return "private";
      if (type === "recovery" && rng() < .22 + anarchyBias) return "private";
      return "sanctioned";
    }

    function makeMission(type, rng, ordinal, opts = {}) {
      const from = currentSystem();
      const starter = !!opts.starter;
      const to = missionDestination(rng, from, type, opts);
      const dist = distance(from, to);
      const heat = Number.isFinite(opts.heat) ? opts.heat : starter ? 0 : type === "naval" ? 3 + Math.floor(rng() * 2) : type === "recovery" ? 2 + Math.floor(rng() * 2) : type === "suppression" ? 1 + Math.floor(rng() * 3) : type === "cargo" ? Math.floor(rng() * 3) : type === "bounty" ? 1 + Math.floor(rng() * 2) : Math.floor(rng() * 2);
      const issuer = missionChoice(rng, MISSION_ISSUERS[type] || MISSION_ISSUERS.courier);
      const id = `m-${game.galaxy}-${from.index}-${missionState().dockSerial}-${ordinal}-${Math.floor(rng() * 0xffffff).toString(36)}`;
      const suppressionRequired = type === "suppression"
        ? clamp(Math.trunc(Number.isFinite(opts.suppressionKills) ? opts.suppressionKills : 3 + Math.floor(rng() * 8) + Math.floor(heat / 2)), 2, 10)
        : 0;
      const encounterRequired = type === "traderDefence" || type === "navalBattle"
        ? clamp(Math.trunc(Number.isFinite(opts.encounterRequired) ? opts.encounterRequired : (type === "navalBattle" ? 2 : 3) + Math.floor(rng() * 3) + Math.floor(heat / 3)), 2, type === "navalBattle" ? 5 : 7)
        : 0;
      const rewardCredits = Number.isFinite(opts.rewardCredits) ? opts.rewardCredits : missionRewardBase(type, dist, rng, heat, opts) + suppressionRequired * 85 + encounterRequired * (type === "navalBattle" ? 160 : 105);
      const legalClass = opts.legalClass || (starter ? "sanctioned" : missionLegalClass(type, rng));
      const mission = {
        id,
        type,
        legalClass,
        issuer,
        title: "",
        description: "",
        origin: systemRef(from),
        destination: systemRef(to),
        distanceLy: Math.round(dist * 10) / 10,
        heat,
        reward: {
          credits: rewardCredits,
          rankPoints: Number.isFinite(opts.rankPoints) ? opts.rankPoints : starter ? 1 : type === "naval" || type === "navalBattle" ? 4 + Math.floor(dist / 14) : type === "suppression" || type === "traderDefence" ? Math.max(2, Math.ceil((suppressionRequired || encounterRequired) / 3)) : type === "bounty" || type === "recovery" ? 2 : 1,
          legalClearance: opts.legalClearance !== undefined ? opts.legalClearance : legalClass === "private" ? 0 : type === "naval" || type === "navalBattle" ? "clean" : type === "suppression" || type === "traderDefence" ? 3 : type === "bounty" ? 4 : type === "cargo" ? 2 : 1
        },
        status: "board"
      };
      if (type === "naval" || type === "navalBattle") {
        mission.reward.navalReputation = Number.isFinite(opts.navalReputation) ? opts.navalReputation : type === "navalBattle" ? 3 : 2;
      }
      if (opts.rewardEquipment) mission.reward.equipment = opts.rewardEquipment;
      if (opts.rewardShip) mission.reward.ship = opts.rewardShip;
      if (type === "cargo" || type === "courier") {
        const item = starter
          ? opts.cargoItem || missionChoice(rng, MISSION_STARTER_ITEMS)
          : opts.cargoItem || (type === "cargo" ? missionChoice(rng, MISSION_CONTRACT_ITEMS) : "sealed diplomatic packet");
        if (type === "cargo") mission.cargo = { name: item, tons: opts.cargoTons || (starter ? 1 : rng() < .82 ? 1 : 2), held: false, secret: opts.cargoSecret ?? (!starter && heat > 1) };
        mission.title = starter
          ? type === "cargo" ? `${opts.titlePrefix || "Starter freight"} to ${to.name}` : `${opts.titlePrefix || "Starter courier run"} to ${to.name}`
          : type === "cargo" ? `Deliver ${item}` : `Courier dispatch to ${to.name}`;
        mission.description = starter
          ? type === "cargo"
            ? `${issuer} needs ${item} moved to ${to.name}. Low-risk station work; sealed, legal and harmless.`
            : `${issuer} needs a routine data dispatch carried to ${to.name}. Easy local work for a new commander.`
          : type === "cargo"
            ? `${issuer} needs a sealed ${item} moved to ${to.name}. The item is not market cargo and must remain sealed.`
          : `${issuer} requests a discreet data handoff at ${to.name}. No cargo space required.`;
      } else if (type === "suppression") {
        mission.suppression = { required: suppressionRequired, destroyed: 0 };
        mission.title = `Pirate suppression at ${to.name}`;
        mission.description = `${issuer} reports sustained pirate activity around ${to.name}. Destroy ${suppressionRequired} pirate vessel${suppressionRequired === 1 ? "" : "s"} in-system; station records will honour the contract across multiple sorties.`;
      } else if (type === "traderDefence") {
        mission.encounter = {
          id: `${id}-encounter`,
          kind: "traderDefence",
          required: encounterRequired,
          destroyed: 0,
          spawned: false,
          spawnDelay: Number.isFinite(opts.spawnDelay) ? opts.spawnDelay : 2 + rng() * 4,
          allies: Number.isFinite(opts.allies) ? opts.allies : 2 + Math.floor(rng() * 2),
          enemies: Number.isFinite(opts.enemies) ? opts.enemies : encounterRequired + (rng() < .45 ? 1 : 0)
        };
        mission.title = `Trader defence at ${to.name}`;
        mission.description = `${issuer} is rallying a local trader band at ${to.name}. Join their defence wing and destroy ${encounterRequired} pirate raider${encounterRequired === 1 ? "" : "s"} before docking for payment.`;
      } else if (type === "navalBattle") {
        const repRequired = Number.isFinite(opts.navalReputationRequired) ? opts.navalReputationRequired : NAVAL_BATTLE_REP_UNLOCK;
        mission.encounter = {
          id: `${id}-encounter`,
          kind: "navalBattle",
          required: encounterRequired,
          destroyed: 0,
          spawned: false,
          spawnDelay: Number.isFinite(opts.spawnDelay) ? opts.spawnDelay : 2 + rng() * 4,
          allies: Number.isFinite(opts.allies) ? opts.allies : 1 + Math.floor(rng() * 2),
          enemies: Number.isFinite(opts.enemies) ? opts.enemies : encounterRequired,
          navalReputationRequired: repRequired
        };
        mission.title = `Naval battle at ${to.name}`;
        mission.description = `${issuer} requests combat support against alien contacts near ${to.name}. Join the naval wing and destroy ${encounterRequired} alien vessel${encounterRequired === 1 ? "" : "s"}.`;
      } else {
        const model = opts.targetModel || missionTargetModel(rng, type);
        const targetName = opts.targetName || (model === "thargoid"
          ? "THARGOID WARSHIP"
          : `${shipName(model)} "${missionChoice(rng, MISSION_TARGET_NAMES)}"`);
        mission.target = {
          id: `${id}-target`,
          model,
          name: targetName,
          spawned: false,
          destroyed: false,
          spawnDelay: Number.isFinite(opts.spawnDelay) ? opts.spawnDelay : 14 + Math.floor(rng() * 24)
        };
        if (type === "recovery" || type === "naval" || opts.recoveryName) {
          const item = opts.recoveryName || (model === "thargoid" ? "alien alloy panel" : missionChoice(rng, MISSION_RECOVERY_ITEMS));
          mission.recovery = { name: item, tons: 1, held: false, required: true };
        }
        if (type === "naval") {
          mission.loan = opts.loan || (rng() < .55
            ? { id: "navalOverchargeLaser", name: "Overcharged Naval Laser", keepChance: .08 }
            : { id: "navalEcm", name: "Long-range Naval ECM", keepChance: .12 });
          const loanShip = navalLoanShipModel(rng, heat, opts);
          if (loanShip) mission.loanShip = { model: loanShip };
          if (!opts.noRandomSpecialRewards) {
            if (rng() < .16) mission.reward.equipment = "militaryLaser";
          }
        }
        mission.title = type === "naval" ? `Naval action at ${to.name}` : `${legalClass === "private" ? "Private warrant" : "Warrant"}: ${targetName}`;
        mission.description = type === "naval"
          ? `${issuer} reports alien or hostile military activity near ${to.name}. Destroy the assigned target${mission.recovery ? ` and recover the ${mission.recovery.name}` : ""}.`
          : `${issuer} authorises action against ${targetName} in ${to.name}. ${legalClass === "private" ? "Local police may not recognise this warrant." : "Warrant is registered with station authority."}`;
      }
      if (missionHasLoanerShip(mission)) {
        mission.immediateDispatch = true;
        mission.description += ` Immediate dispatch: accepting this contract readies a loaned ${shipName(mission.loanShip.model)} and locks mission progress to this assignment until the ship is returned.`;
      }
      mission.requirements = starter ? [] : missionRequirementsFor(type, dist, heat, mission);
      return mission;
    }

    function generateMissionBoard(force = false) {
      const state = missionState();
      const sys = currentSystem();
      const boardKey = `${game.galaxy}:${sys.index}:${state.dockSerial}`;
      if (!force && state.boardKey === boardKey) return state.board;
      const rng = mulberry(hash32(`mission-board:${game.commander}:${boardKey}:${game.kills}:${Math.floor(game.credits)}`));
      const count = MISSION_BOARD_MIN + Math.floor(rng() * (MISSION_BOARD_MAX - MISSION_BOARD_MIN + 1));
      const board = [];
      const starterSlots = missionRatingScore() < 8 ? 2 : missionRatingScore() < 16 ? 1 : 0;
      for (let i = 0; i < count; i++) {
        if (i < starterSlots) {
          board.push(makeMission(rng() < .55 ? "courier" : "cargo", rng, i, { starter: true }));
          continue;
        }
        let roll = rng();
        const anarchyBias = clamp((3 - sys.government) / 4, 0, .55);
        const corporateBias = clamp(((sys.tech + 1) - 8) / 8, 0, .32) + clamp((sys.productivity - 14000) / 26000, 0, .18);
        const navalBias = clamp(((sys.tech + 1) - 9) / 10, 0, .18) + (sys.government >= 5 ? .04 : 0);
        let type;
        if (roll < .24 - anarchyBias * .08) type = "courier";
        else if (roll < .52 + corporateBias * .16) type = "cargo";
        else if (roll < .76 + anarchyBias * .12) type = "bounty";
        else if (roll < .86 + anarchyBias * .18) type = rng() < .38 ? "traderDefence" : "suppression";
        else if (roll < .975 + anarchyBias * .12 + corporateBias * .06) type = "recovery";
        else type = "naval";
        if (rng() < navalBias * .22) type = navalReputationScore() >= NAVAL_BATTLE_REP_UNLOCK && rng() < .35 ? "navalBattle" : "naval";
        if (type === "naval" && navalReputationScore() >= NAVAL_BATTLE_REP_UNLOCK && rng() < .18) type = "navalBattle";
        board.push(makeMission(type, rng, i));
      }
      state.board = board;
      state.boardKey = boardKey;
      return board;
    }

    function refreshMissionBoardOnDock() {
      const state = missionState();
      state.dockSerial++;
      generateMissionBoard(true);
    }

    function missionLoanActive(id) {
      return missionState().active.some((mission) => mission.status === "active" && mission.loan?.id === id);
    }

    function activeMissionLoanShipFor(model) {
      return missionState().active.find((mission) =>
        mission.status === "active"
        && missionHasLoanerShip(mission)
        && mission.loanShip.model === model
      ) || null;
    }

    function grantMissionLoanShip(mission) {
      const model = mission?.loanShip?.model;
      if (!isDockyardShipModel(model)) return true;
      missionState();
      const activeLoan = activeImmediateDispatchMission();
      if (activeLoan) {
        eliteAudio.play("boop");
        setMessage(`Return ${shipName(activeLoan.loanShip.model)} before accepting another mission ship.`, true);
        return false;
      }
      const cargoCap = shipCargoCap(model);
      const pendingCargo = mission.cargo?.held ? Number(mission.cargo.tons) || 0 : 0;
      const totalCargo = usedCargo() + pendingCargo;
      if (totalCargo > cargoCap) {
        eliteAudio.play("boop");
        setMessage(`Mission ship ${shipName(model)} has only ${cargoCap}t cargo space. Sell cargo first.`, true);
        return false;
      }
      const wasOwned = ownedShipList().includes(model);
      mission.loanShip = {
        ...mission.loanShip,
        model,
        previousShip: playerShipModel(),
        wasOwned,
        keep: false
      };
      if (!game.missionUnlocks.ships.includes(model)) game.missionUnlocks.ships.push(model);
      if (!game.missionUnlocks.ownedShips.includes(model)) game.missionUnlocks.ownedShips.push(model);
      game.playerShip = model;
      applyPlayerShipStats({ trimCargo: false });
      restoreShipSystems();
      shipDiagramState.model = model;
      return true;
    }

    function revokeMissionLoanShip(mission) {
      const loan = mission?.loanShip;
      if (!loan?.model || loan.keep || loan.wasOwned) return;
      missionState();
      const fallback = ownedShipList().find((model) => model !== loan.model)
        || (isDockyardShipModel(loan.previousShip) ? loan.previousShip : "cobra");
      if (playerShipModel() === loan.model) {
        game.playerShip = fallback;
        applyPlayerShipStats({ trimCargo: false });
        restoreShipSystems();
        shipDiagramState.model = fallback;
      }
      game.missionUnlocks.ownedShips = game.missionUnlocks.ownedShips.filter((model) => model !== loan.model);
    }

    function acceptMission(id) {
      const state = missionState();
      if (!game.docked) return setMessage("Mission board is station-side only.", true);
      const activeDispatch = activeImmediateDispatchMission();
      if (activeDispatch) {
        eliteAudio.play("boop");
        return setMessage(`Immediate dispatch active: complete ${activeDispatch.title} before accepting another contract.`, true);
      }
      if (state.active.filter((m) => m.status === "active").length >= MISSION_MAX_ACTIVE) {
        eliteAudio.play("boop");
        return setMessage("Mission ledger full.", true);
      }
      const idx = state.board.findIndex((mission) => mission.id === id);
      if (idx < 0) return;
      const mission = JSON.parse(JSON.stringify(state.board[idx]));
      if (missionHasLoanerShip(mission) && state.active.some((m) => m.status === "active")) {
        eliteAudio.play("boop");
        return setMessage("Immediate dispatch requires a clear mission ledger. Complete or abandon active contracts first.", true);
      }
      const cargoTons = Number(mission.cargo?.tons) || 0;
      const devBypass = devBypassesMissionRequirements();
      const missing = missingMissionRequirements(mission);
      if (missing.length) {
        eliteAudio.play("boop");
        return setMessage(`Ship specifications not up to contract: ${missing.map((req) => req.label).join(", ")} required.`, true);
      }
      if (!devBypass && cargoTons && usedCargo() + cargoTons > game.cargoCap) {
        eliteAudio.play("boop");
        return setMessage("Insufficient cargo space for sealed mission item.", true);
      }
      mission.status = "active";
      mission.acceptedAt = { galaxy: game.galaxy, system: game.current };
      if (mission.cargo) mission.cargo.held = true;
      if (!grantMissionLoanShip(mission)) return;
      state.board.splice(idx, 1);
      state.active.push(mission);
      if (missionHasLoanerShip(mission)) syncImmediateDispatchCourse();
      eliteAudio.play("beep");
      const devNote = devBypass ? " Dev mode bypassed contract requirements." : "";
      setMessage((mission.loanShip
        ? `${MISSION_TYPES[mission.type] || "Mission"} accepted: ${mission.title}. Immediate dispatch: ${shipName(mission.loanShip.model)} readied; course locked to ${mission.destination?.name || "mission destination"}.`
        : `${MISSION_TYPES[mission.type] || "Mission"} accepted: ${mission.title}.`) + devNote, true);
      renderPanel();
    }

    function abandonMission(id) {
      const mission = activeMissionById(id);
      if (!mission) return;
      mission.status = "failed";
      mission.failedReason = "Abandoned by commander";
      clearImmediateDispatchCourse(mission);
      revokeMissionLoanShip(mission);
      clearMissionCommsHistory(mission);
      eliteAudio.play("boop");
      setMessage(`Mission abandoned: ${mission.title}.`, true);
      renderPanel();
    }

    function missionEquipmentName(id) {
      if (id === "navalOverchargeLaser") return "Overcharged Naval Laser";
      if (id === "navalEcm") return "Long-range Naval ECM";
      return EQUIPMENT.find((e) => e.id === id)?.name || id || "equipment";
    }

    function buildMissionCompletionDebrief(mission, details) {
      const reward = mission.reward || {};
      const lines = [];
      const commander = `Commander ${game.commander || "Jameson"}`;
      if (mission.legalClass === "military" || mission.type === "naval") {
        lines.push(`Thanks for your service, ${commander}. Sector command confirms that ${mission.title} is complete.`);
      } else if (mission.type === "bounty" || mission.type === "recovery" || mission.type === "suppression") {
        lines.push(`Contract closed, ${commander}. ${mission.issuer || "The issuer"} confirms the target work is complete.`);
      } else {
        lines.push(`Thank you, ${commander}. ${mission.issuer || "The mission office"} confirms delivery at ${mission.destination?.name || currentSystem().name}.`);
      }
      lines.push(`We have credited your account with ${fmt(reward.credits || 0)} CR.`);
      if (reward.rankPoints) lines.push(`Your Elite service record has been increased by ${reward.rankPoints} point${reward.rankPoints === 1 ? "" : "s"}.`);
      if (reward.navalReputation) lines.push(`Your naval reputation has increased by ${reward.navalReputation} point${reward.navalReputation === 1 ? "" : "s"}.`);
      if (reward.legalClearance === "clean") lines.push("Your legal record has been cleared under mission authority.");
      else if (reward.legalClearance) lines.push(`Your legal record has been reduced by ${reward.legalClearance} point${reward.legalClearance === 1 ? "" : "s"}.`);
      if (details.equipmentAward) lines.push(`The ${details.equipmentAward} is now yours to keep.`);
      if (details.shipAward) lines.push(`The loaned ${details.shipAward} has been released to your permanent shipyard inventory.`);
      else if (details.shipLoanName) lines.push(`The loaned ${details.shipLoanName} has been returned to naval stores.`);
      if (details.loanName) {
        lines.push(details.loanKept
          ? `Command has decided to let you retain the loaned ${details.loanName}.`
          : `The loaned ${details.loanName} has been returned to mission stores.`);
      }
      return lines.join(" ");
    }

    function completeMission(mission) {
      if (!mission || mission.status !== "active") return false;
      mission.status = "complete";
      mission.completedAt = { galaxy: game.galaxy, system: game.current };
      const reward = mission.reward || {};
      const details = {
        credits: Number(reward.credits) || 0,
        rankPoints: Number(reward.rankPoints) || 0,
        legalClearance: reward.legalClearance || 0,
        equipmentAward: "",
        shipAward: "",
        navalReputation: Number(reward.navalReputation) || 0,
        shipLoanName: mission.loanShip?.model && !mission.loanShip.wasOwned ? shipName(mission.loanShip.model) : "",
        shipLoanKept: false,
        loanName: mission.loan?.name || "",
        loanKept: false
      };
      game.credits += Number(reward.credits) || 0;
      game.missionRankPoints = (Number(game.missionRankPoints) || 0) + (Number(reward.rankPoints) || 0);
      game.navalReputation = Math.max(0, (Number(game.navalReputation) || 0) + (Number(reward.navalReputation) || 0));
      if (reward.legalClearance === "clean") game.legal = 0;
      else game.legal = Math.max(0, game.legal - (Number(reward.legalClearance) || 0));
      if (reward.equipment) {
        details.equipmentAward = missionEquipmentName(reward.equipment);
        if (game.equipment[reward.equipment] === false) {
          if (isLaserEquipment(reward.equipment)) fitLaser(reward.equipment);
          else game.equipment[reward.equipment] = true;
        }
      }
      if (reward.ship && SHIP_NAMES[reward.ship]) {
        details.shipAward = shipName(reward.ship);
        if (!game.missionUnlocks.ships.includes(reward.ship)) game.missionUnlocks.ships.push(reward.ship);
        if (isDockyardShipModel(reward.ship) && !game.missionUnlocks.ownedShips.includes(reward.ship)) {
          game.missionUnlocks.ownedShips.push(reward.ship);
        }
        if (mission.loanShip?.model === reward.ship) {
          mission.loanShip.keep = true;
          details.shipLoanKept = true;
        }
      }
      if (mission.loan?.keepChance && Math.random() < mission.loan.keepChance) {
        details.loanKept = true;
        if (mission.loan.id === "navalOverchargeLaser") {
          fitLaser("militaryLaser");
          mission.rewardKeptLoan = "Military Laser";
          details.loanName = mission.rewardKeptLoan;
        } else if (mission.loan.id === "navalEcm") {
          game.equipment.ecm = true;
          mission.rewardKeptLoan = "E.C.M. System";
          details.loanName = mission.rewardKeptLoan;
        }
      }
      if (mission.loanShip?.model && !mission.loanShip.keep) revokeMissionLoanShip(mission);
      clearImmediateDispatchCourse(mission);
      mission.completionDetails = details;
      mission.completionMessage = buildMissionCompletionDebrief(mission, details);
      missionState().completed++;
      clearMissionCommsHistory(mission);
      return true;
    }

    function missionCompletionBlockers(mission) {
      if (!mission) return ["Mission record unavailable"];
      if (mission.status !== "active") return [`Mission is ${String(mission.status || "inactive").toUpperCase()}`];
      if (!missionProgressUnlocked(mission)) {
        const dispatch = activeImmediateDispatchMission();
        return [`Immediate dispatch active: complete ${dispatch?.title || "the loaned-ship assignment"} first`];
      }
      const blockers = [];
      if (!sameSystemRef(mission.destination)) {
        blockers.push(`Dock at ${mission.destination?.name || "the destination system"}`);
        return blockers;
      }
      if (mission.type === "courier") return blockers;
      if (mission.cargo && !mission.cargo.held) blockers.push(`${mission.cargo.name || "Sealed cargo"} is not aboard`);
      if (mission.suppression) {
        const required = Number(mission.suppression.required) || 1;
        const destroyed = Number(mission.suppression.destroyed) || 0;
        if (destroyed < required) blockers.push(`Destroy ${required - destroyed} more pirate vessel${required - destroyed === 1 ? "" : "s"}`);
      }
      if (mission.encounter) {
        const required = Number(mission.encounter.required) || 1;
        const destroyed = Number(mission.encounter.destroyed) || 0;
        if (destroyed < required) {
          const subject = mission.encounter.kind === "navalBattle" ? "alien contact" : "raider";
          blockers.push(`Destroy or rout ${required - destroyed} more ${subject}${required - destroyed === 1 ? "" : "s"}`);
        }
      }
      if (mission.target && !mission.target.destroyed) {
        blockers.push(mission.target.spawned ? `Destroy ${mission.target.name || "the mission target"}` : `Locate ${mission.target.name || "the mission target"} in-system`);
      }
      if (mission.recovery?.required && !mission.recovery.held) {
        blockers.push(`Recover ${mission.recovery.name}`);
      }
      return blockers;
    }

    function missionReadyForDockCompletion(mission) {
      return missionCompletionBlockers(mission).length === 0;
    }

    function pendingDockedMissionMessages() {
      return missionState().active
        .filter((mission) => mission.status === "active" && missionProgressUnlocked(mission) && sameSystemRef(mission.destination))
        .map((mission) => {
          const blockers = missionCompletionBlockers(mission);
          return blockers.length ? `${mission.title}: ${blockers[0]}` : "";
        })
        .filter(Boolean);
    }

    function completeDockedMissions({ announce = true, queueDialogs = true, detailed = false } = {}) {
      const completed = [];
      const dispatch = activeImmediateDispatchMission();
      for (const mission of missionState().active) {
        if (dispatch && mission.id !== dispatch.id) continue;
        if (!missionProgressUnlocked(mission)) continue;
        if (!missionReadyForDockCompletion(mission)) continue;
        if (completeMission(mission)) completed.push(mission);
      }
      if (!completed.length) return detailed ? { message: "", completed: [], pending: pendingDockedMissionMessages() } : "";
      const total = completed.reduce((sum, mission) => sum + (Number(mission.reward?.credits) || 0), 0);
      const names = completed.map((mission) => mission.title).slice(0, 2).join("; ");
      if (announce) commsMessage("MISSION OFFICE", `Completion confirmed: ${names}. ${fmt(total)} CR authorised.`, "mission");
      if (queueDialogs) queueMissionCompleteDialogs(completed);
      const message = `${completed.length} mission${completed.length === 1 ? "" : "s"} completed. ${fmt(total)} CR paid.`;
      return detailed ? { message, completed, pending: pendingDockedMissionMessages() } : message;
    }

    function failActiveMissions(reason) {
      let failed = 0;
      for (const mission of missionState().active) {
        if (mission.status !== "active") continue;
        mission.status = "failed";
        mission.failedReason = reason;
        clearImmediateDispatchCourse(mission);
        revokeMissionLoanShip(mission);
        clearMissionCommsHistory(mission);
        failed++;
      }
      return failed;
    }

    function missionLegalDisposition(o) {
      const mission = o?.missionId ? activeMissionById(o.missionId) : null;
      if (!mission) return null;
      if (!missionProgressUnlocked(mission)) return null;
      if (o.missionEncounterSide === "ally") return null;
      if (mission.legalClass === "military" || mission.legalClass === "sanctioned") return "authorised";
      return "private";
    }

    function missionAuthorisesAttackOn(o) {
      return missionLegalDisposition(o) === "authorised";
    }

    function playerMayEngageWithoutStationPenalty(o) {
      if (!o || o.type !== "ship") return false;
      if (missionAuthorisesAttackOn(o)) return true;
      if (!o.hostile || o.police || o.role === "police" || o.role === "trader") return false;
      const profile = SOURCE_BEHAVIOUR[o.model] || {};
      return !(profile.innocent || profile.trader || profile.hauler || profile.timid);
    }

    function activeSuppressionMissionsHere() {
      return missionState().active.filter((mission) =>
        mission.status === "active"
        && missionProgressUnlocked(mission)
        && mission.type === "suppression"
        && mission.suppression
        && sameSystemRef(mission.destination)
        && (Number(mission.suppression.destroyed) || 0) < (Number(mission.suppression.required) || 1)
      );
    }

    function pirateSuppressionEligibleKill(o) {
      return !!o && o.type === "ship" && o.hostile && o.role === "pirate" && !o.police && !isAlienShip(o);
    }

    function recordPirateSuppressionKill(o) {
      if (!pirateSuppressionEligibleKill(o)) return [];
      const updated = [];
      for (const mission of activeSuppressionMissionsHere()) {
        const required = Number(mission.suppression.required) || 1;
        mission.suppression.destroyed = clamp((Number(mission.suppression.destroyed) || 0) + 1, 0, required);
        updated.push(mission);
      }
      return updated;
    }

    function spawnMissionDrop(target, mission) {
      const cargo = mission.recovery;
      if (!cargo || cargo.dropped || cargo.held) return;
      cargo.dropped = true;
      const stats = shipStats("canister");
      game.objects.push(protectFreshDropFromLaser({
        type: "canister",
        model: "canister",
        name: `MISSION CARGO: ${cargo.name.toUpperCase()}`,
        missionCargo: { missionId: mission.id, name: cargo.name, tons: cargo.tons || 1 },
        protectedMissionCargo: true,
        pos: add(target.pos, vec(0, 0, 34)),
        vel: vec(0, 0, -14),
        rot: 0,
        pitch: 0,
        r: stats.r,
        color: "#8fe8ff",
        hp: stats.hp,
        hostile: false
      }));
    }

    function markMissionTargetDestroyed(o) {
      const mission = o?.missionId ? activeMissionById(o.missionId) : null;
      if (!mission?.target || mission.target.id !== o.missionTargetId) return null;
      if (!missionProgressUnlocked(mission)) return null;
      mission.target.destroyed = true;
      mission.target.spawned = false;
      if (mission.recovery?.required) spawnMissionDrop(o, mission);
      return mission;
    }

    function liveMissionTarget(mission) {
      if (!mission?.target?.id) return null;
      return worldSnapshot().ships.find((ship) =>
        ship.type === "ship"
        && !ship._remove
        && ship.missionId === mission.id
        && ship.missionTargetId === mission.target.id
      ) || null;
    }

    function scoopMissionCargo(o) {
      const cargo = o?.missionCargo;
      const mission = cargo?.missionId ? activeMissionById(cargo.missionId) : null;
      if (!mission?.recovery) return false;
      if (!missionProgressUnlocked(mission)) {
        const dispatch = activeImmediateDispatchMission();
        setMessage(`Immediate dispatch active: complete ${dispatch?.title || "the loaned-ship assignment"} before recovering other mission cargo.`, true);
        return true;
      }
      const tons = Number(cargo.tons) || 1;
      if (usedCargo() + tons > game.cargoCap) {
        setMessage("Cargo bay full. Mission item not recovered.", true);
        return true;
      }
      mission.recovery.held = true;
      mission.recovery.tons = tons;
      game.objects = game.objects.filter((x) => x !== o);
      eliteAudio.play("cargoScoop");
      missionCommsMessage(mission, `${cargo.name} recovered. Return to ${mission.destination?.name || currentSystem().name} station for hand-in.`);
      setMessage(`Recovered mission item: ${cargo.name}.`, true);
      renderPanel();
      return true;
    }

    function missionSpawnPoint(rng, radius = 1800) {
      const fwd = forwardVector(game.camera);
      const q = ensureCameraQuat(game.camera);
      const right = quatRotate(q, vec(1, 0, 0));
      const up = quatRotate(q, vec(0, 1, 0));
      return add(game.camera.pos, add(scale(fwd, radius + rng() * 900), add(scale(right, (rng() - .5) * 900), scale(up, (rng() - .5) * 520))));
    }

    function spawnMissionTarget(mission) {
      if (!mission?.target || mission.target.spawned || mission.target.destroyed) return null;
      const rng = mulberry(hash32(`mission-spawn:${mission.id}:${game.galaxy}:${game.current}:${Math.floor(performance.now() / 1000)}`));
      const model = MODELS[mission.target.model] ? mission.target.model : "krait";
      const stats = shipStats(model);
      const thargoid = model === "thargoid";
      const hostile = true;
      const role = thargoid ? "alien" : "pirate";
      const o = {
        type: "ship",
        model,
        name: mission.target.name || shipName(model),
        pos: missionSpawnPoint(rng, thargoid ? 2400 : 1700),
        vel: vec((rng() - .5) * 34, (rng() - .5) * 28, -28 - rng() * 38),
        rot: rng() * TAU,
        pitch: rng() * TAU,
        roll: rng() * TAU,
        r: stats.r,
        color: thargoid ? "#d9f1c0" : shipColor(model, false),
        hp: Math.round(stats.hp * (thargoid ? 1.2 : mission.type === "naval" ? 1.15 : 1.05)),
        maxHp: Math.round(stats.hp * (thargoid ? 1.2 : mission.type === "naval" ? 1.15 : 1.05)),
        hostile,
        police: false,
        role,
        bounty: 0,
        thargoid,
        missionId: mission.id,
        missionTargetId: mission.target.id,
        aiMode: "attack",
        target: null,
        orbitCenter: { ...game.camera.pos },
        orbitRadius: 900 + rng() * 700,
        orbitAngle: rng() * TAU,
        orbitSpeed: (rng() > .5 ? 1 : -1) * (.22 + rng() * .25),
        attackClock: rng() * .8,
        wobble: rng() * TAU,
        npcMissiles: npcMissileStock(model, role, false),
        decalSeed: hash32(`mission:${mission.id}:${model}`)
      };
      setNoseDirection(o, sub(game.camera.pos, o.pos), o.roll);
      game.objects.push(o);
      mission.target.spawned = true;
      mission.target.spawnSystem = { galaxy: game.galaxy, system: game.current };
      missionCommsMessage(mission, thargoid ? "Alien contact confirmed. Engage under naval warrant." : `${o.name} transponder spike detected. Contract authority active.`);
      setMessage(`Mission contact detected: ${o.name}.`, true);
      if (game.panelOpen && game.panel === "missions") renderPanel();
      return o;
    }

    function liveMissionEncounterShips(mission, side = "") {
      if (!mission?.encounter?.id) return [];
      return worldSnapshot().ships.filter((ship) =>
        ship.type === "ship"
        && !ship._remove
        && ship.missionId === mission.id
        && ship.missionEncounterId === mission.encounter.id
        && (!side || ship.missionEncounterSide === side)
      );
    }

    function missionEncounterProgressMessage(mission) {
      const encounter = mission?.encounter;
      if (!encounter) return "";
      const required = Number(encounter.required) || 1;
      const destroyed = Number(encounter.destroyed) || 0;
      const subject = encounter.kind === "navalBattle" ? "alien contacts" : "raiders";
      return destroyed >= required
        ? `${MISSION_TYPES[mission.type] || "Mission"} complete (${destroyed}/${required} ${subject}). Dock for payment.`
        : `${MISSION_TYPES[mission.type] || "Mission"} progress ${destroyed}/${required} ${subject}.`;
    }

    function recordMissionEncounterKill(o) {
      if (!o || o._missionEncounterRecorded || o.missionEncounterSide !== "enemy" || !o.missionId || !o.missionEncounterId) return null;
      const mission = activeMissionById(o.missionId);
      const encounter = mission?.encounter;
      if (!missionProgressUnlocked(mission)) return null;
      if (!encounter || encounter.id !== o.missionEncounterId || !sameSystemRef(mission.destination)) return null;
      o._missionEncounterRecorded = true;
      const required = Number(encounter.required) || 1;
      encounter.destroyed = clamp((Number(encounter.destroyed) || 0) + 1, 0, required);
      return mission;
    }

    function missionEncounterModel(kind, side, rng) {
      if (kind === "navalBattle") {
        if (side === "ally") return missionChoice(rng, ["viper", "asp", "ferdelance"].filter((model) => MODELS[model]));
        return rng() < .74 ? "thargoid" : "thargon";
      }
      return side === "ally"
        ? missionChoice(rng, ["cobra", "cobra1", "python", "boa", "adder", "gecko"].filter((model) => MODELS[model]))
        : missionChoice(rng, PIRATE_MODELS.filter((model) => MODELS[model]));
    }

    function missionEncounterArrivalPlan(kind, side, index, count, rng) {
      if (kind === "navalBattle" && side === "enemy") return { hyperspaceIn: false, delay: 0 };
      if (kind === "navalBattle" && side === "ally") {
        return index === 0
          ? { hyperspaceIn: false, delay: 0 }
          : { hyperspaceIn: true, delay: 1.4 + index * (2.1 + rng() * 1.2) + rng() * 2.4 };
      }
      if (kind === "traderDefence" && side === "enemy") {
        const present = Math.max(1, Math.ceil(count * .55));
        return index < present
          ? { hyperspaceIn: false, delay: 0 }
          : { hyperspaceIn: true, delay: 1.2 + (index - present) * (3.1 + rng() * 1.6) + rng() * 3.2 };
      }
      if (side === "ally") {
        return index === 0 || rng() < .35
          ? { hyperspaceIn: false, delay: 0 }
          : { hyperspaceIn: true, delay: 1.8 + index * (2.4 + rng() * 1.4) + rng() * 2.8 };
      }
      return rng() < .5
        ? { hyperspaceIn: false, delay: 0 }
        : { hyperspaceIn: true, delay: 1.5 + index * 2.7 + rng() * 3.5 };
    }

    function spawnMissionEncounterShip(mission, side, index, center, rng) {
      const encounter = mission.encounter;
      const kind = encounter.kind;
      const model = missionEncounterModel(kind, side, rng) || (side === "ally" ? "cobra" : "krait");
      const stats = shipStats(model);
      const count = Math.max(1, side === "ally" ? Number(encounter.allies) || 1 : Number(encounter.enemies) || Number(encounter.required) || 1);
      const angle = (index / count) * TAU + (side === "enemy" ? Math.PI : 0) + rng() * .38;
      const spread = side === "ally" ? 220 + rng() * 240 : 520 + rng() * 420;
      const vertical = (rng() - .5) * (kind === "navalBattle" ? 260 : 180);
      const pos = add(center, vec(Math.cos(angle) * spread, vertical, Math.sin(angle) * spread));
      const drift = norm(add(sub(center, pos), vec((rng() - .5) * 120, (rng() - .5) * 80, (rng() - .5) * 120)));
      const alien = ALIEN_MODELS.includes(model);
      const navalAlly = kind === "navalBattle" && side === "ally";
      const role = side === "ally" ? (navalAlly ? "naval" : "trader") : (alien ? "alien" : "pirate");
      const hostile = side === "enemy";
      const hpScale = side === "ally" ? (navalAlly ? 1.08 : .95) : alien ? 1.08 : 1.05;
      const o = {
        type: "ship",
        model,
        name: side === "ally"
          ? `${navalAlly ? "NAVAL" : "TRADER"} ${shipName(model)}`
          : `${alien ? "ALIEN" : "PIRATE"} ${shipName(model)}`,
        pos,
        vel: scale(drift, 55 + rng() * 38),
        rot: rng() * TAU,
        pitch: rng() * TAU,
        roll: rng() * TAU,
        r: stats.r,
        color: alien ? "#d9f1c0" : shipColor(model, role === "police"),
        hp: Math.round(stats.hp * hpScale),
        maxHp: Math.round(stats.hp * hpScale),
        hostile,
        police: false,
        role,
        bounty: hostile && !alien ? 60 + Math.floor(rng() * 95) : alien ? 50 : 0,
        thargoid: model === "thargoid",
        thargon: model === "thargon",
        missionId: mission.id,
        missionEncounterId: encounter.id,
        missionEncounterSide: side,
        missionAlly: side === "ally",
        aiMode: "attack",
        target: undefined,
        orbitCenter: center,
        orbitRadius: spread,
        orbitAngle: angle,
        orbitSpeed: (rng() > .5 ? 1 : -1) * (.2 + rng() * .24),
        attackClock: .45 + rng() * 1.2,
        wobble: rng() * TAU,
        npcMissiles: npcMissileStock(model, role, false),
        decalSeed: hash32(`mission-encounter:${mission.id}:${side}:${index}:${model}`)
      };
      setNoseDirection(o, side === "enemy" ? sub(game.camera.pos, o.pos) : o.vel, o.roll);
      const arrival = missionEncounterArrivalPlan(kind, side, index, count, rng);
      if (arrival.hyperspaceIn) {
        startNpcHyperspaceIn(o, { dur: 1.22 + rng() * .32, revealAt: .62 + rng() * .12, delay: arrival.delay });
      }
      game.objects.push(o);
      return o;
    }

    function spawnMissionEncounter(mission) {
      const encounter = mission?.encounter;
      if (!encounter || encounter.spawned || (Number(encounter.destroyed) || 0) >= (Number(encounter.required) || 1)) return [];
      const rng = mulberry(hash32(`mission-encounter:${mission.id}:${game.galaxy}:${game.current}:${Math.floor(performance.now() / 1000)}`));
      const center = missionSpawnPoint(rng, encounter.kind === "navalBattle" ? 2450 : 1850);
      const allies = [];
      const enemies = [];
      for (let i = 0; i < (Number(encounter.allies) || 1); i++) allies.push(spawnMissionEncounterShip(mission, "ally", i, center, rng));
      for (let i = 0; i < (Number(encounter.enemies) || Number(encounter.required) || 1); i++) enemies.push(spawnMissionEncounterShip(mission, "enemy", i, center, rng));
      for (let i = 0; i < allies.length; i++) allies[i].target = enemies[i % Math.max(1, enemies.length)] || null;
      for (let i = 0; i < enemies.length; i++) enemies[i].target = allies.length && rng() < .76 ? allies[i % allies.length] : null;
      encounter.spawned = true;
      encounter.spawnSystem = { galaxy: game.galaxy, system: game.current };
      const message = encounter.kind === "navalBattle"
        ? "Alien contacts already in-system. Naval wing is joining in staggered jumps."
        : "Raider group already in-system. Trader defenders and pirate reinforcements are joining unevenly.";
      missionCommsMessage(mission, message);
      setMessage(`Mission encounter detected: ${mission.title}.`, true);
      if (game.panelOpen && game.panel === "missions") renderPanel();
      return [...allies, ...enemies];
    }

    function updateMissionSpawns(dt) {
      if (game.docked || game.transition || game.jumpCountdown) return;
      for (const mission of missionState().active) {
        if (mission.status !== "active") continue;
        if (!missionProgressUnlocked(mission)) continue;
        if (!sameSystemRef(mission.destination)) continue;
        if (mission.suppression && (Number(mission.suppression.destroyed) || 0) < (Number(mission.suppression.required) || 1)) {
          if (!mission.suppression.initialPresence && !stationSafeZoneActive()) {
            const liveShipCount = worldSnapshot().ships.filter((ship) => ship.type === "ship" && !ship._remove && ship.role !== "pod").length;
            const spawned = spawnSuppressionPirates(mulberry(hash32(`mission-suppression-initial:${mission.id}:${game.galaxy}:${game.current}`)), liveShipCount, { initial: true });
            if (spawned) {
              mission.suppression.initialPresence = true;
              for (const active of activeSuppressionMissionsHere()) {
                if (active.suppression && sameSystemRef(active.destination)) active.suppression.initialPresence = true;
              }
              missionCommsMessage(mission, "Pirate contacts already active in-system. Additional raiders may jump in.");
            }
          }
        }
        if (mission.encounter && (Number(mission.encounter.destroyed) || 0) < (Number(mission.encounter.required) || 1)) {
          if (mission.encounter.spawned && !liveMissionEncounterShips(mission, "enemy").length) {
            const required = Number(mission.encounter.required) || 1;
            const remaining = Math.max(1, required - (Number(mission.encounter.destroyed) || 0));
            mission.encounter.spawned = false;
            mission.encounter.enemies = Math.max(remaining, Number(mission.encounter.enemies) || remaining);
            mission.encounter.spawnDelay = Math.min(Number(mission.encounter.spawnDelay) || 8, 8);
            setMessage("Mission contacts lost. Reacquiring hostile group.", true);
            missionCommsMessage(mission, "Mission contacts lost. Reacquiring hostile group.", { durationMs: 14000 });
          }
          if (mission.encounter.spawned) continue;
          mission.encounter.spawnDelay = Math.max(0, (Number(mission.encounter.spawnDelay) || 0) - dt);
          if (mission.encounter.spawnDelay <= 0) {
            try {
              spawnMissionEncounter(mission);
            } catch (err) {
              console.error("Mission encounter spawn failed", err);
              mission.encounter.spawned = false;
              mission.encounter.spawnDelay = 8;
              setMessage("Mission encounter signal unstable. Reacquiring contacts.", true);
              missionCommsMessage(mission, "Mission encounter signal unstable. Reacquiring contacts.", { durationMs: 14000 });
            }
          }
          continue;
        }
        if (!mission.target || mission.target.destroyed) continue;
        if (mission.target.spawned && !liveMissionTarget(mission)) {
          mission.target.spawned = false;
          mission.target.spawnDelay = Math.min(Number(mission.target.spawnDelay) || 8, 8);
          setMessage("Mission contact lost. Reacquiring target signal.", true);
          missionCommsMessage(mission, "Mission contact lost. Reacquiring target signal.", { durationMs: 14000 });
        }
        if (mission.target.spawned) continue;
        mission.target.spawnDelay = Math.max(0, (Number(mission.target.spawnDelay) || 0) - dt);
        const world = worldSnapshot();
        const bodies = Array.isArray(world?.bodies)
          ? world.bodies
          : Array.isArray(world?.largeBodies)
            ? world.largeBodies
            : Array.isArray(world?.objects)
              ? world.objects.filter((body) => body?.type === "planet" || body?.type === "sun" || body?.type === "station")
              : [];
        const nearBody = bodies.some((body) =>
          finiteVec3(body?.pos)
          && finiteVec3(game.camera?.pos)
          && len(sub(body.pos, game.camera.pos)) < (body.r || 500) + 2600
        );
        if (mission.target.spawnDelay <= 0 || nearBody) {
          try {
            spawnMissionTarget(mission);
          } catch (err) {
            console.error("Mission target spawn failed", err);
            mission.target.spawned = false;
            mission.target.spawnDelay = 8;
            setMessage("Mission contact signal unstable. Reacquiring target.", true);
            missionCommsMessage(mission, "Mission contact signal unstable. Reacquiring target.", { durationMs: 14000 });
          }
        }
      }
    }

    const alienGlyphCache = new Map();
    const commsSenderThrottle = new Map();
    let commsSeq = 0;
    const COMMS_KIND_RULES = {
      mission: { duration: 15500, protected: true },
      station: { duration: 9500, protected: true },
      warning: { duration: 11500, protected: true }
    };
    const COMMS_HISTORY_FILTERS = [
      { id: "important", label: "IMPORTANT", match: (m) => ["mission", "warning", "police", "hostile", "alien"].includes(m.kind) || m.alien },
      { id: "mission", label: "MISSION", match: (m) => m.kind === "mission" },
      { id: "security", label: "SECURITY", match: (m) => ["warning", "police", "hostile", "alien"].includes(m.kind) || m.alien },
      { id: "all", label: "ALL COMMS", match: () => true }
    ];
    const COMMS_HISTORY_LIMIT = 160;

    function inferCommsKind(from, alien = false) {
      const name = String(from || "").toUpperCase();
      if (alien) return "alien";
      if (name.includes("CONTROL") || name.includes("TRAFFIC")) return "station";
      if (name.includes("POLICE") || name.includes("VIPER") || name.includes("PATROL")) return "police";
      if (name.includes("PIRATE")) return "hostile";
      if (name.includes("TRADER") || name.includes("ARMADA")) return "trader";
      return "trader";
    }

    function commsMessage(from, text, alienOrKind = false, opts = {}) {
      if (HACK_DISABLE_CHATTER) return false;
      const alien = alienOrKind === true || alienOrKind === "alien";
      const kind = typeof alienOrKind === "string" ? alienOrKind : inferCommsKind(from, alien);
      const now = performance.now();
      const throttleKey = `${kind}:${from}`;
      const recent = commsSenderThrottle.get(throttleKey);
      const rule = COMMS_KIND_RULES[kind] || {};
      const protectedComms = !!(opts.protected || rule.protected);
      if (!protectedComms && recent && now - recent.at < 4200) {
        if (recent.text === text || now - recent.at < 1800) return false;
      }
      commsSenderThrottle.set(throttleKey, { text, at: now });
      const duration = Number.isFinite(opts.durationMs) ? opts.durationMs : rule.duration || 9500;
      const msg = {
        id: ++commsSeq,
        from,
        text,
        alien,
        kind,
        born: now,
        until: now + duration,
        missionId: opts.missionId || ""
      };
      game.comms.push(msg);
      if (game.comms.length > 5) game.comms.splice(0, game.comms.length - 5);
      recordCommsHistory(msg, now);
      renderComms();
      return true;
    }

    function resetCommsHistoryForLaunch() {
      const carryMissionHistory = (Array.isArray(game.commsHistory) ? game.commsHistory : [])
        .filter((msg) => msg.missionId && activeMissionById(msg.missionId));
      game.comms = [];
      game.commsHistory = carryMissionHistory;
      game.commsLaunchAt = performance.now();
      game.commsReviewOpen = false;
      game.commsReviewOffset = 0;
      renderComms();
      renderCommsReview();
    }

    function recordCommsHistory(msg, now = performance.now()) {
      if (!Array.isArray(game.commsHistory)) game.commsHistory = [];
      if (!game.commsLaunchAt) game.commsLaunchAt = now;
      game.commsHistory.push({
        id: msg.id,
        from: msg.from,
        text: msg.text,
        alien: !!msg.alien,
        kind: msg.kind || "trader",
        missionId: msg.missionId || "",
        born: msg.born || now,
        system: currentSystem().name
      });
      if (game.commsHistory.length > COMMS_HISTORY_LIMIT) game.commsHistory.splice(0, game.commsHistory.length - COMMS_HISTORY_LIMIT);
      renderCommsReview();
    }

    function commsHistoryFilter() {
      return COMMS_HISTORY_FILTERS.find((filter) => filter.id === game.commsReviewFilter) || COMMS_HISTORY_FILTERS[0];
    }

    function filteredCommsHistory() {
      const filter = commsHistoryFilter();
      return (Array.isArray(game.commsHistory) ? game.commsHistory : []).filter(filter.match);
    }

    function formatCommsHistoryTime(msg) {
      const base = game.commsLaunchAt || msg.born || performance.now();
      const elapsed = Math.max(0, Math.floor(((msg.born || base) - base) / 1000));
      const minutes = Math.floor(elapsed / 60);
      const seconds = String(elapsed % 60).padStart(2, "0");
      return `+${minutes}:${seconds}`;
    }

    function updateCommsToggle() {
      const btn = hudEls.commsToggle;
      if (!btn) return;
      btn.classList.toggle("active", !!game.commsReviewOpen);
      btn.setAttribute("aria-expanded", String(!!game.commsReviewOpen));
      btn.title = game.commsReviewOpen ? "Close comms panel" : "Open comms panel";
    }

    function attachCommsReviewControls(el) {
      el.querySelectorAll("[data-comms-scroll]").forEach((button) => {
        button.addEventListener("click", (e) => {
          scrollCommsHistory(Number(button.dataset.commsScroll) || 0);
          e.stopPropagation();
        });
      });
      el.querySelectorAll("[data-comms-filter]").forEach((button) => {
        button.addEventListener("click", (e) => {
          cycleCommsHistoryFilter(Number(button.dataset.commsFilter) || 1);
          e.stopPropagation();
        });
      });
      const close = el.querySelector("[data-comms-close]");
      if (close) close.addEventListener("click", (e) => {
        toggleCommsReview(false);
        e.stopPropagation();
      });
    }

    function renderCommsReview() {
      const el = byId("commsReview");
      if (!el) return;
      if (!game.commsReviewOpen) {
        el.hidden = true;
        if (el.dataset.renderKey !== "closed") {
          el.dataset.renderKey = "closed";
          el.innerHTML = "";
        }
        updateCommsToggle();
        return;
      }
      const filter = commsHistoryFilter();
      const items = filteredCommsHistory();
      const key = `${filter.id}:${items.map((m) => m.id).join(",")}`;
      if (el.dataset.renderKey === key) return;
      const oldLog = el.querySelector("[data-comms-log]");
      const wasPinnedToLatest = !oldLog || oldLog.scrollTop + oldLog.clientHeight >= oldLog.scrollHeight - 6;
      const filterChanged = !String(el.dataset.renderKey || "").startsWith(`${filter.id}:`);
      el.hidden = false;
      el.dataset.renderKey = key;
      const count = `${items.length} ${items.length === 1 ? "MESSAGE" : "MESSAGES"}`;
      const lines = items.length ? items.map((m) => {
        const kindClass = m.alien ? "alien-comms" : `comms-${escapeAttr(m.kind || "trader")}`;
        const body = m.alien ? alienGlyphMarkup(m.text) : escapeHtml(m.text);
        return `<div class="comms-review-line ${kindClass}"><span class="comms-review-time">${formatCommsHistoryTime(m)}</span><span class="comms-review-kind">${escapeHtml(m.kind || "trader")}</span><span class="comms-review-text"><span class="comms-from">${escapeHtml(m.from)}:</span> ${body}</span></div>`;
      }).join("") : `<div class="comms-review-line"><span class="comms-review-time">--</span><span class="comms-review-kind">${escapeHtml(filter.id)}</span><span class="comms-review-text">No matching comms since launch.</span></div>`;
      el.innerHTML = `<div class="comms-review-head">
        <span>COMMS / ${escapeHtml(filter.label)}</span>
        <span class="comms-review-controls">
          <button class="btn mini" type="button" data-comms-filter="1" title="Next comms filter">F</button>
          <button class="btn mini" type="button" data-comms-close title="Close comms panel">×</button>
          <span>${count}</span>
        </span>
      </div><div class="comms-review-log" data-comms-log>${lines}</div>`;
      updateCommsToggle();
      attachCommsReviewControls(el);
      const log = el.querySelector("[data-comms-log]");
      if (log && (wasPinnedToLatest || filterChanged)) log.scrollTop = log.scrollHeight;
    }

    function cycleCommsHistoryFilter(dir = 1) {
      const current = COMMS_HISTORY_FILTERS.findIndex((filter) => filter.id === game.commsReviewFilter);
      const next = (current + dir + COMMS_HISTORY_FILTERS.length) % COMMS_HISTORY_FILTERS.length;
      game.commsReviewFilter = COMMS_HISTORY_FILTERS[next].id;
      game.commsReviewOffset = 0;
      renderCommsReview();
      setMessage(`Comms filter: ${COMMS_HISTORY_FILTERS[next].label}.`);
    }

    function scrollCommsHistory(dir = 1) {
      const log = byId("commsReview")?.querySelector("[data-comms-log]");
      if (!log) {
        renderCommsReview();
        return;
      }
      const step = Math.max(90, log.clientHeight * 0.82);
      log.scrollBy({ top: dir > 0 ? -step : step, behavior: "smooth" });
    }

    function toggleCommsReview(force = undefined) {
      game.commsReviewOpen = force === undefined ? !game.commsReviewOpen : !!force;
      game.commsReviewOffset = 0;
      renderCommsReview();
      setMessage(`Comms history: ${game.commsReviewOpen ? commsHistoryFilter().label.toLowerCase() : "closed"}.`);
    }

    function missionCommsMessage(mission, text, opts = {}) {
      const from = mission?.issuer || "MISSION OFFICE";
      return commsMessage(from, text, "mission", { durationMs: opts.durationMs ?? 15500, protected: true, missionId: mission?.id || "" });
    }

    function clearMissionCommsHistory(missionOrId) {
      const missionId = typeof missionOrId === "string" ? missionOrId : missionOrId?.id;
      if (!missionId || !Array.isArray(game.commsHistory)) return;
      game.commsHistory = game.commsHistory.filter((msg) => msg.missionId !== missionId);
      renderCommsReview();
    }

    function missionAmbientLine(mission) {
      if (!mission) return "";
      const type = MISSION_TYPES[mission.type] || "Mission";
      const dest = mission.destination?.name || currentSystem().name;
      const here = sameSystemRef(mission.destination);
      if (!here) {
        if (mission.cargo?.held) return pick([
          `${type} packet remains sealed. Destination remains ${dest}.`,
          `Contract beacon confirms cargo custody. Route to ${dest}.`,
          `Mission traffic note: keep the manifest sealed until ${dest}.`
        ]);
        return pick([
          `${type} contract still tagged for ${dest}.`,
          `Mission office repeats destination: ${dest}.`,
          `Contract beacon idle. Next useful report expected in ${dest} space.`
        ]);
      }
      if (missionReadyForDockCompletion(mission)) return pick([
        `${type} objective satisfied. Dock for payment.`,
        `Mission office confirms completion state. Return to station services.`,
        `Contract beacon green. Payment pending at dock.`
      ]);
      if (mission.encounter) {
        const required = Number(mission.encounter.required) || 1;
        const destroyed = Number(mission.encounter.destroyed) || 0;
        const left = Math.max(0, required - destroyed);
        return mission.encounter.kind === "navalBattle"
          ? pick([
            `Naval tactical: ${left} alien contact${left === 1 ? "" : "s"} remain on contract scope.`,
            `Military channel holds your engagement warrant. Alien count ${destroyed}/${required}.`,
            `Wing telemetry requests continued support. ${left} hostile contact${left === 1 ? "" : "s"} unresolved.`
          ])
          : pick([
            `Convoy channel: ${left} raider${left === 1 ? "" : "s"} still threatening the traders.`,
            `Trader band beacon shows ${destroyed}/${required} raiders cleared.`,
            `Contract traffic asks you to keep the convoy covered. ${left} raider${left === 1 ? "" : "s"} remain.`
          ]);
      }
      if (mission.suppression) {
        const required = Number(mission.suppression.required) || 1;
        const destroyed = Number(mission.suppression.destroyed) || 0;
        return pick([
          `Suppression warrant active. Pirate count ${destroyed}/${required}.`,
          `Station security still wants ${Math.max(0, required - destroyed)} pirate contact${required - destroyed === 1 ? "" : "s"} cleared.`,
          `Patrol net is crediting your pirate kills. Current tally ${destroyed}/${required}.`
        ]);
      }
      if (mission.target && !mission.target.destroyed) return mission.target.spawned
        ? pick([
          `${mission.target.name || "Mission target"} transponder is live. Engage under contract authority.`,
          `Target beacon remains hot. Bring down ${mission.target.name || "the contact"}.`,
          `Mission office confirms target in-system. Weapons authority unchanged.`
        ])
        : pick([
          `Mission signal search active. Stand by for ${mission.target.name || "target"} transponder spike.`,
          `Contract scanner sweep continuing in ${dest} space.`,
          `Mission office has no clean target lock yet. Keep scanners open.`
        ]);
      if (mission.recovery?.required && !mission.recovery.held) return pick([
        `Recovery item still outstanding: ${mission.recovery.name}.`,
        `Mission cargo beacon has not been recovered. Search debris carefully.`,
        `${mission.recovery.name} must be recovered before payment clears.`
      ]);
      return `${type} contract active. Monitor mission board for blockers.`;
    }

    function pickMissionCommsCandidate() {
      const active = missionState().active.filter((mission) => mission.status === "active");
      if (!active.length) return null;
      const here = active.filter((mission) => sameSystemRef(mission.destination));
      return pick(here.length ? here : active);
    }

    function alienGlyphSvg(ch) {
      const key = ch.toUpperCase();
      if (alienGlyphCache.has(key)) return alienGlyphCache.get(key);
      const rng = mulberry(hash32(`alien-glyph:${key}`));
      const anchors = [
        [2, 2], [5, 1.4], [8, 2],
        [2, 6], [5, 6], [8, 6],
        [2, 12], [5, 12.6], [8, 12]
      ];
      const lineCount = 2 + Math.floor(rng() * 3);
      const used = new Set();
      const parts = [];
      for (let i = 0; i < lineCount; i++) {
        let a = Math.floor(rng() * anchors.length);
        let b = Math.floor(rng() * anchors.length);
        for (let guard = 0; guard < 8 && (a === b || used.has(`${Math.min(a, b)}:${Math.max(a, b)}`)); guard++) b = Math.floor(rng() * anchors.length);
        if (a === b) continue;
        used.add(`${Math.min(a, b)}:${Math.max(a, b)}`);
        parts.push(`<line x1="${anchors[a][0].toFixed(1)}" y1="${anchors[a][1].toFixed(1)}" x2="${anchors[b][0].toFixed(1)}" y2="${anchors[b][1].toFixed(1)}"></line>`);
      }
      if (rng() > .48) {
        const c = anchors[Math.floor(rng() * anchors.length)];
        parts.push(`<circle class="${rng() > .55 ? "filled" : ""}" cx="${c[0].toFixed(1)}" cy="${c[1].toFixed(1)}" r="${(1 + rng() * 1.15).toFixed(1)}"></circle>`);
      }
      if (rng() > .68) {
        const side = rng() > .5 ? 1 : -1;
        parts.push(`<path d="M ${side > 0 ? 2 : 8} 3 Q 5 ${2 + rng() * 9} ${side > 0 ? 8 : 2} 11"></path>`);
      }
      const svg = `<svg class="alien-glyph" viewBox="0 0 10 14" aria-hidden="true">${parts.join("")}</svg>`;
      alienGlyphCache.set(key, svg);
      return svg;
    }

    function alienGlyphMarkup(text) {
      let html = "";
      for (const ch of String(text)) {
        if (/\s/.test(ch)) html += `<span class="alien-space"></span>`;
        else if (/[A-Z]/i.test(ch)) html += alienGlyphSvg(ch);
        else if (ch === "'") html += `<span class="alien-punct">·</span>`;
        else if (ch === "/") html += `<span class="alien-punct">∕</span>`;
        else if (ch === "?") html += `<span class="alien-punct">⌁</span>`;
        else if (ch === "!") html += `<span class="alien-punct">⌇</span>`;
        else if (ch === "…") html += `<span class="alien-punct">⋯</span>`;
        else html += `<span class="alien-punct">${escapeHtml(ch)}</span>`;
      }
      return `<span class="alien-text" title="${escapeAttr(text)}" aria-label="${escapeAttr(text)}">${html}</span>`;
    }

    function renderComms() {
      const el = byId("commsLog");
      if (!el) return;
      if (HACK_DISABLE_CHATTER) {
        if (game.comms.length) game.comms = [];
        if (el.dataset.renderKey !== "muted") {
          el.dataset.renderKey = "muted";
          if (el.innerHTML) el.innerHTML = "";
        }
        return;
      }
      const now = performance.now();
      const live = game.comms.filter((m) => m.until > now);
      if (live.length !== game.comms.length) game.comms = live;
      const newest = live[live.length - 1];
      const renderState = live.map((m) => `${m.id}:${Math.min(String(m.text).length, Math.floor(Math.max(0, now - (m.born || 0)) / 18))}`).join("|");
      const key = `${renderState}:${newest ? newest.id : 0}`;
      if (el.dataset.renderKey === key) return;
      el.dataset.renderKey = key;
      el.innerHTML = live.map((m) => {
        const typed = Math.min(String(m.text).length, Math.floor(Math.max(0, now - (m.born || 0)) / 18));
        const visibleText = String(m.text).slice(0, typed);
        const body = m.alien ? alienGlyphMarkup(visibleText) : escapeHtml(visibleText);
        const kindClass = m.alien ? "alien-comms" : `comms-${escapeAttr(m.kind || "trader")}`;
        const cursor = m === newest ? `<span class="comms-cursor">_</span>` : "";
        return `<div class="comms-line ${kindClass}"><span class="comms-from">${escapeHtml(m.from)}:</span> ${body}${cursor}</div>`;
      }).join("");
    }
    if (!ULTRA_ELITE_RENDER_BENCH) setInterval(renderComms, 120);

    function isAlienShip(o) {
      return !!o && (o.thargoid || ALIEN_MODELS.includes(o.model));
    }

    function alienNeverFlees(o) {
      return isAlienShip(o);
    }

    function shipHyperspaceHidden(o) {
      return !!o?._hyperspaceHidden;
    }

    const ALIEN_BASE_ALPHABET = "ZXQKVRTHNGMLPDSWYFJCBAXUO".split("");

    function alienAlphabet() {
      const rng = mulberry(hash32(`alien-alphabet:${game.galaxy}:${currentSystem().index}`));
      const chars = ALIEN_BASE_ALPHABET.slice();
      for (let i = chars.length - 1; i > 0; i--) {
        const j = Math.floor(rng() * (i + 1));
        [chars[i], chars[j]] = [chars[j], chars[i]];
      }
      return chars.slice(0, 25);
    }

    function alienWord(rng, alphabet, min = 2, max = 6) {
      const len = min + Math.floor(rng() * (max - min + 1));
      let out = "";
      for (let i = 0; i < len; i++) {
        out += alphabet[Math.floor(rng() * alphabet.length)];
        if (i > 0 && i < len - 1 && rng() < .18) out += "'";
      }
      return out;
    }

    function alienChatterLine(o, mood = "ambient") {
      const seed = hash32(`${currentSystem().name}:${o?.name || "alien"}:${mood}:${Math.floor(performance.now() / 2400)}`);
      const rng = mulberry(seed);
      const alphabet = alienAlphabet();
      const words = 3 + Math.floor(rng() * 5);
      let text = Array.from({ length: words }, (_, i) => alienWord(rng, alphabet, i === 0 ? 3 : 2, mood === "threat" ? 7 : 6)).join(" ");
      if (mood === "threat") text = `${alienWord(rng, alphabet, 5, 8)} // ${text}`;
      if (mood === "flee") text = `${text} ? ${alienWord(rng, alphabet, 3, 5)}`;
      if (mood === "mercy") text = `${alienWord(rng, alphabet, 4, 7)} ? ${text} ? ${alienWord(rng, alphabet, 3, 5)}`;
      return text + pick(["", "", "", "!", "…"]);
    }

    const hail = (o, text) => commsMessage(o.name || "UNKNOWN", text, isAlienShip(o) ? "alien" : o.police ? "police" : o.hostile ? "hostile" : "trader");
    const stationCommsName = () => `${currentSystem().name.toUpperCase()} CONTROL`;

    function shipHail(o, mood, text, chance = 1, cooldown = 9000) {
      if (!o || Math.random() > chance) return false;
      const now = performance.now();
      o._hailTimes = o._hailTimes || {};
      if (o._hailTimes[mood] && now - o._hailTimes[mood] < cooldown) return false;
      o._hailTimes[mood] = now;
      return hail(o, text);
    }

    function governmentCommsTone() {
      const gov = currentSystem().government;
      if (gov === 0) return "anarchy";
      if (gov === 1) return "feudal";
      if (gov === 2) return "multi";
      if (gov === 3) return "dictatorship";
      if (gov === 4) return "communist";
      if (gov === 5) return "confederacy";
      if (gov === 6) return "democracy";
      if (gov === 7) return "corporate";
      return "neutral";
    }

    function toneLines(map) {
      return (map[governmentCommsTone()] || map.neutral || []).concat(map.any || []);
    }

    function hostileThreatLine(o) {
      const sys = currentSystem();
      if (isAlienShip(o)) return alienChatterLine(o, "threat");
      return pick([
        `Cargo and credits, ${game.commander}, and you keep breathing.`,
        `Fresh meat on the ${sys.name} lanes!`,
        `That ${shipName(playerShipModel())} will strip for parts nicely.`,
        "Nothing personal. Scrap prices are up.",
        `${GOVS[sys.government]} law can't save you out here.`,
        "Your transponder just became negotiable.",
        "Power down and dump the hold. Try anything clever and burn.",
        `I know a fence at ${sys.name} who'll pay for your hull plates.`,
        "Nice cargo profile. Shame about the escort.",
        "Running only makes the salvage colder."
      ]);
    }

    function fleeLine(o) {
      if (isAlienShip(o)) return alienChatterLine(o, "flee");
      return o.hostile
        ? pick([
          "This isn't over, pilot!",
          "Breaking off — that one's a demon!",
          "Not worth the paint. I'm gone.",
          "Engines redlining. Disengaging.",
          "Keep the cargo, keep the curse.",
          "Next time I bring friends."
        ])
        : pick([
          "Mayday! Mayday! Under fire!",
          `Any police in ${currentSystem().name} sector?! Help!`,
          "I'm just a hauler! Hold your fire!",
          "Ceasing manoeuvres! Don't shoot!",
          "My insurer is going to love this.",
          "Control, logging hostile contact now!"
        ]);
    }

    function attackedFleeLine(o, profile = {}) {
      if (isAlienShip(o)) return alienChatterLine(o, "flee");
      if (profile.timid || ["shuttle", "transporter", "worm"].includes(o.model)) {
        return pick([
          "Civilian vessel under fire! Breaking lane!",
          "No weapons aboard! We are disengaging!",
          "Control, this is a shuttle taking fire!",
          "Transport manifest emergency! Fleeing contact!",
          "We are non-combat traffic! Hold your fire!",
          "Crew compartment hit! Running for beacon cover!"
        ]);
      }
      if (profile.hauler || o.role === "trader") {
        return pick([
          "Hauler under attack. Dumping vector and running!",
          "Cargo insured, hull isn't. We're leaving!",
          "Freighter breaking off. Marking attacker hostile.",
          "Control, commercial vessel fleeing weapons fire!",
          "No cargo is worth this. Engines to emergency thrust.",
          "Escort contract clearly expired. We are out."
        ]);
      }
      return pick([
        "Taking fire. Disengaging!",
        "Hull strike logged. Running cold!",
        "Not my fight. Breaking contact.",
        "Vectoring away from hostile commander.",
        "Shields unstable. I'm gone."
      ]);
    }

    function retaliationLine(o, profile = {}) {
      if (isAlienShip(o)) return alienChatterLine(o, "threat");
      if (o.police || o.role === "police") return pick([
        "Assault on Viper patrol. Weapons free.",
        "Commander, you have fired on police. Stand by for enforcement.",
        "Viper unit hit. Pursuit authority granted.",
        "Patrol shields struck. Returning fire.",
        "Criminal assault confirmed. Engaging."
      ]);
      if (profile.bountyHunter) return pick([
        "Bad choice, commander. I was hunting bigger game.",
        "You just made the bounty board.",
        "Bounty hunter returning fire.",
        "Assault logged. I'll collect the fine from your wreck.",
        "You wanted my attention. You have it."
      ]);
      if (profile.pirate || o.hostile) return pick([
        "You shoot first? I respect that.",
        "Now it's personal, commander.",
        "Fine. No cargo deal. Just wreckage.",
        "You'll pay for that scratch.",
        "Weapons hot. Coming about."
      ]);
      return pick([
        "Self-defence systems live. Back off!",
        "You fired on the wrong ship.",
        "Warning ignored. Returning fire.",
        "I don't want this fight, but I'll finish it.",
        "Hostile act confirmed. Engaging."
      ]);
    }

    function assaultReportLine(o, profile = {}) {
      if (profile.timid) return pick([
        `${o.name} reports civilian vessel under attack.`,
        `Emergency beacon from ${o.name}: weapons impact logged.`,
        `${o.name} requests immediate patrol support.`,
        `Control copies distress call from ${o.name}.`
      ]);
      if (profile.hauler || o.role === "trader") return pick([
        `${o.name} reports commercial traffic under fire.`,
        `Freighter distress beacon received from ${o.name}.`,
        `${o.name} has marked attacker hostile on trade net.`,
        `Control copies cargo vessel assault report from ${o.name}.`
      ]);
      return pick([
        `${o.name} reports illegal weapons strike.`,
        `Assault report received from ${o.name}.`,
        `${o.name} transponder marks hostile contact.`,
        `Weapons impact logged by ${o.name}.`
      ]);
    }

    function mercyLine(o, attackerName = game.commander) {
      if (isAlienShip(o)) return alienChatterLine(o, "mercy");
      if (o.role === "police" || o.police) {
        return pick([
          "Mayday! Viper hull breach, losing control!",
          "Officer down! Request emergency recovery!",
          "Patrol unit crippled. Any friendly contact, respond!",
          `${attackerName}, cease fire! Pilot survival priority!`,
          "Command, shields gone. I need cover now!"
        ]);
      }
      if (o.hostile) {
        return pick([
          "Wait! Wait! I can pay!",
          "Hold fire, commander! Cargo is yours!",
          "Engines are gone! Let me drift!",
          "No more shots! I'll dump the hold!",
          "Mercy! I yield, I yield!",
          "Take the bounty if you must, just leave the pod!"
        ]);
      }
      return pick([
        "Please, hold fire! I'm venting atmosphere!",
        "I surrender! Cargo, credits, anything!",
        "My reactor is cracking! Let me eject!",
        "Ceasing thrust! Please don't finish this!",
        "I'm just a trader! Please, no more!",
        `${attackerName}, I have crew aboard! Hold fire!`
      ]);
    }

    function maybeHailMercy(o, attackerName = game.commander, chance = 1) {
      if (!o || o.type !== "ship" || !o.maxHp || o.hp <= 0 || o._mercyHailed) return;
      const hullFrac = o.hp / o.maxHp;
      if (hullFrac > .16 || Math.random() > chance) return;
      o._mercyHailed = true;
      hail(o, mercyLine(o, attackerName));
    }

    function shipHitReactionChance(o, profile) {
      if (o.police || o.role === "police") return 1;
      if (o.thargoid || isAlienShip(o)) return 1;
      if (o.hostile || profile.pirate || profile.hostile) return .94;
      if (profile.bountyHunter) return .82;
      if (profile.timid || o.role === "pod") return .08;
      if (profile.hauler || o.role === "trader") return .28;
      return .45;
    }

    function reactToPlayerAttack(o) {
      if (!o || o.type !== "ship" || o.role === "pod" || o.hp <= 0) return;
      if (playerMayEngageWithoutStationPenalty(o)) {
        o.hostile = true;
        o.target = null;
        o.aiMode = "attack";
        o.attackClock = Math.min(o.attackClock || .35, .28 + Math.random() * .55);
        return;
      }
      const profile = SOURCE_BEHAVIOUR[o.model] || {};
      const innocent = profile.innocent || (!o.hostile && (o.role === "trader" || profile.trader || profile.hauler || profile.timid));
      if (innocent && !o._reportedAssault) {
        o._reportedAssault = true;
        game.legal = Math.min(60, game.legal + (profile.timid ? 5 : 8));
        commsMessage(stationCommsName(), assaultReportLine(o, profile), "station");
        if (nearStationSafeZone()) provokeStationPolice(`${o.name} attacked near the station`);
        else if (Math.random() < .42) spawnPoliceResponse();
      }

      const hullFrac = o.maxHp ? o.hp / o.maxHp : 1;
      const shouldFlee = !o.police && !alienNeverFlees(o) && (
        o.role === "trader" ||
        profile.timid ||
        profile.hauler ||
        (innocent && hullFrac < .72)
      );
      const fightChance = shipHitReactionChance(o, profile);
      if (shouldFlee && Math.random() > fightChance) {
        o.hostile = false;
        o.target = null;
        o.aiMode = "flee";
        o.fleeFrom = { ...game.camera.pos };
        o.fleeAge = 0;
        o._fleeCommitted = true;
        if (!o._fleeHailed) {
          o._fleeHailed = true;
          shipHail(o, "flee", attackedFleeLine(o, profile), .92, 12000);
        }
        return;
      }

      if (Math.random() <= fightChance) {
        o.hostile = true;
        o.target = null;
        o.aiMode = "attack";
        o.attackClock = Math.min(o.attackClock || .35, .28 + Math.random() * .55);
        o._fleeCommitted = false;
        if (o.role === "trader" && !profile.timid && !profile.hauler) o.role = "retaliating";
        if (!o._retaliationHailed) {
          o._retaliationHailed = true;
          hail(o, retaliationLine(o, profile));
        }
      }
    }

