    function writeBrowserSave(silent = false) {
      if (!canSaveCommander()) {
        if (!silent) setMessage("Save unavailable in flight. Dock first.", true);
        return false;
      }
      try {
        localStorage.setItem(SAVE_KEY, JSON.stringify(commanderSaveData()));
      } catch {
        if (!silent) setMessage("Browser save storage unavailable.");
        return false;
      }
      if (!silent) setMessage("Commander saved to browser storage.", true);
      return true;
    }

    function saveGame() {
      return writeBrowserSave(false);
    }

    function browserSaveExists() {
      try {
        return !!localStorage.getItem(SAVE_KEY);
      } catch {
        return false;
      }
    }

    function loadBrowserSave(silent = false) {
      let raw = null;
      try {
        raw = localStorage.getItem(SAVE_KEY);
      } catch {
        if (!silent) setMessage("Browser save storage unavailable.");
        return false;
      }
      if (!raw) {
        if (!silent) setMessage("No saved commander found.");
        return false;
      }
      try {
        applyCommanderSave(JSON.parse(raw));
        if (!silent) setMessage("Commander loaded.", true);
        renderPanel();
        return true;
      } catch {
        if (!silent) setMessage("Commander file corrupted.");
        return false;
      }
    }

    function loadGame() {
      loadBrowserSave(false);
    }

    function restoreCommanderAfterGameOver(reason) {
      const commander = normalizeCommanderName(game.commander);
      const hadBrowserSave = browserSaveExists();
      if (hadBrowserSave && loadBrowserSave(true)) {
        resetFlightScene(false);
        setMessage(`Ship destroyed by ${reason}. Browser commander save restored.`, true);
        renderPanel();
        return;
      }
      applyCommanderSave(freshCommanderSaveData(commander));
      resetFlightScene(false);
      setMessage(
        hadBrowserSave
          ? `Ship destroyed by ${reason}. Browser save failed; new Lave commander record created.`
          : `Ship destroyed by ${reason}. New Lave commander record created.`,
        true
      );
      renderPanel();
    }

    function deleteBrowserSave() {
      try {
        localStorage.removeItem(SAVE_KEY);
        setMessage("Browser save deleted.", true);
      } catch {
        setMessage("Browser save storage unavailable.");
      }
      renderPanel();
    }

    function saveFilename() {
      const name = String(game.commander || "commander").trim().toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || "commander";
      return `ultra-elite-${name}.uelite`;
    }

    function downloadCommanderFile() {
      if (!canSaveCommander()) {
        setMessage("Commander export unavailable in flight. Dock first.", true);
        return;
      }
      downloadText(saveFilename(), encodeCommanderSaveFile(commanderSaveData()));
      setMessage("Commander file downloaded.", true);
    }

    function uploadCommanderFile(file) {
      if (!file) return;
      const reader = new FileReader();
      reader.onload = () => {
        try {
          const data = decodeCommanderSaveFile(reader.result || "");
          applyCommanderSave(data);
          localStorage.setItem(SAVE_KEY, JSON.stringify(commanderSaveData()));
          setMessage(`Commander loaded from ${file.name}.`, true);
          renderPanel();
        } catch {
          setMessage("Commander file corrupted.");
        }
      };
      reader.onerror = () => setMessage("Could not read commander file.");
      reader.readAsText(file);
    }

